--
-- Name: _criteria_avgs_for_project(uuid, uuid, jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public._criteria_avgs_for_project(p_project_id uuid, p_semester_id uuid, p_template jsonb) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
BEGIN
  RETURN (
    SELECT COALESCE(jsonb_object_agg(key, avg_val), '{}'::jsonb) FROM (
      SELECT c->>'key' AS key,
        ROUND(AVG((sc2.criteria_scores->>(c->>'key'))::numeric), 2) AS avg_val
      FROM jsonb_array_elements(COALESCE(p_template, '[]'::jsonb)) c
      LEFT JOIN scores sc2 ON sc2.project_id = p_project_id AND sc2.semester_id = p_semester_id
        AND sc2.criteria_scores IS NOT NULL AND sc2.final_submitted_at IS NOT NULL
        AND EXISTS (SELECT 1 FROM juror_semester_auth a2
          WHERE a2.juror_id = sc2.juror_id AND a2.semester_id = sc2.semester_id
            AND COALESCE(a2.edit_enabled, false) = false)
      GROUP BY c->>'key'
    ) sub
  );
END; $$;


--
-- Name: _derive_score_status(jsonb, jsonb, boolean, timestamp with time zone, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public._derive_score_status(p_criteria jsonb, p_template jsonb, p_edit boolean, p_final timestamp with time zone, p_comment text) RETURNS text
    LANGUAGE plpgsql IMMUTABLE
    AS $$
BEGIN
  IF p_criteria IS NOT NULL
     AND (p_template IS NULL OR jsonb_array_length(p_template) = 0
          OR (SELECT bool_and(p_criteria->>(t->>'key') IS NOT NULL) FROM jsonb_array_elements(p_template) t))
  THEN
    IF p_final IS NOT NULL THEN RETURN 'completed'; END IF;
    IF COALESCE(p_edit, false) THEN RETURN 'editing'; END IF;
    RETURN 'submitted';
  END IF;
  IF (p_criteria IS NULL OR p_criteria = '{}'::jsonb)
     AND NULLIF(trim(coalesce(p_comment, '')), '') IS NULL
  THEN RETURN 'not_started'; END IF;
  RETURN 'in_progress';
END; $$;


--
-- Name: _dispatch_application_notification(text, uuid, text, uuid, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public._dispatch_application_notification(p_type text, p_application_id uuid, p_recipient_email text, p_tenant_id uuid, p_applicant_name text DEFAULT NULL::text, p_tenant_short_label text DEFAULT NULL::text) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE
  v_url text;
  v_auth text;
  v_host text;
  v_applicant_email text;
BEGIN
  SELECT lower(trim(a.applicant_email))
    INTO v_applicant_email
  FROM tenant_admin_applications a
  WHERE a.id = p_application_id
  LIMIT 1;

  BEGIN
    -- Preferred sources: DB setting, then Vault secret.
    v_url := current_setting('app.settings.supabase_url', true);
    IF v_url IS NULL OR trim(v_url) = '' THEN
      BEGIN
        SELECT decrypted_secret
          INTO v_url
        FROM vault.decrypted_secrets
        WHERE name = 'supabase_url'
        ORDER BY created_at DESC
        LIMIT 1;
      EXCEPTION WHEN OTHERS THEN
        v_url := NULL;
      END;
    END IF;

    -- Last resort: infer host from request headers when called via PostgREST RPC.
    IF v_url IS NULL OR trim(v_url) = '' THEN
      BEGIN
        v_host := (current_setting('request.headers', true)::jsonb ->> 'host');
        IF v_host IS NOT NULL AND trim(v_host) <> '' THEN
          IF left(trim(v_host), 9) = 'localhost'
             OR left(trim(v_host), 9) = '127.0.0.1' THEN
            v_url := 'http://' || trim(v_host);
          ELSE
            v_url := 'https://' || trim(v_host);
          END IF;
        END IF;
      EXCEPTION WHEN OTHERS THEN
        v_url := NULL;
      END;
    END IF;

    -- Optional auth for function calls (works when verify_jwt is enabled).
    -- Support both legacy/lowercase and uppercase secret naming conventions.
    BEGIN
      v_auth := current_setting('app.settings.supabase_service_role_key', true);
      IF v_auth IS NULL OR trim(v_auth) = '' THEN
        SELECT decrypted_secret
          INTO v_auth
        FROM vault.decrypted_secrets
        WHERE name IN ('supabase_service_role_key', 'SUPABASE_SERVICE_ROLE_KEY')
        ORDER BY created_at DESC
        LIMIT 1;
      END IF;
    EXCEPTION WHEN OTHERS THEN
      v_auth := NULL;
    END;

    IF v_url IS NOT NULL AND v_url <> '' THEN
      PERFORM net.http_post(url := v_url || '/functions/v1/notify-application',
        body := jsonb_build_object('type', p_type, 'application_id', p_application_id,
          'recipient_email', p_recipient_email, 'tenant_id', p_tenant_id,
          'applicant_name', p_applicant_name, 'applicant_email', v_applicant_email, 'tenant_name', p_tenant_short_label),
        headers := CASE
          WHEN v_auth IS NOT NULL AND trim(v_auth) <> '' THEN
            jsonb_build_object('Content-Type', 'application/json', 'Authorization', 'Bearer ' || trim(v_auth))
          ELSE
            jsonb_build_object('Content-Type', 'application/json')
        END);
    ELSE
      PERFORM public._audit_log('system', NULL, 'notification_failed', 'tenant_admin_application', p_application_id,
        'Notification skipped: supabase URL not resolved.',
        jsonb_build_object('type', p_type, 'tenant_id', p_tenant_id, 'recipient_email', p_recipient_email));
    END IF;
  EXCEPTION WHEN OTHERS THEN
    PERFORM public._audit_log('system', NULL, 'notification_failed', 'tenant_admin_application', p_application_id,
      'Notification dispatch failed.',
      jsonb_build_object('type', p_type, 'tenant_id', p_tenant_id, 'recipient_email', p_recipient_email, 'error', SQLERRM));
  END;
END; $$;


