--
-- Name: _verify_rpc_secret(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public._verify_rpc_secret(p_provided text) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE v_expected text;
BEGIN
  SELECT decrypted_secret INTO v_expected FROM vault.decrypted_secrets WHERE name = 'rpc_secret' LIMIT 1;
  IF v_expected IS NULL OR v_expected = '' THEN
    RAISE EXCEPTION 'unauthorized: rpc_secret not configured' USING ERRCODE = 'insufficient_privilege'; END IF;
  IF p_provided IS DISTINCT FROM v_expected THEN
    RAISE EXCEPTION 'unauthorized: rpc_secret mismatch' USING ERRCODE = 'insufficient_privilege'; END IF;
END; $$;


--
-- Name: notify_super_admin_on_application(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.notify_super_admin_on_application() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE
  v_resend_key  text;
  v_super_email text;
  v_to_array    jsonb;
  v_subject     text;
  v_html        text;
  v_tenant_code text;
BEGIN
  SELECT decrypted_secret INTO v_resend_key
  FROM vault.decrypted_secrets
  WHERE name = 'resend_api_key'
  LIMIT 1;

  IF v_resend_key IS NULL THEN
    RAISE WARNING 'notify_super_admin: resend_api_key vault secret not found';
    RETURN NEW;
  END IF;

  SELECT code INTO v_tenant_code
  FROM public.tenants
  WHERE id = NEW.tenant_id;

  v_to_array := '[]'::jsonb;
  FOR v_super_email IN
    SELECT DISTINCT u.email
    FROM auth.users u
    INNER JOIN public.admin_profiles ap ON ap.user_id = u.id
    LEFT JOIN public.tenant_admin_memberships tam ON tam.user_id = u.id
    WHERE tam.user_id IS NULL
      AND u.email IS NOT NULL
  LOOP
    v_to_array := v_to_array || jsonb_build_array(v_super_email);
  END LOOP;

  IF jsonb_array_length(v_to_array) = 0 THEN
    RAISE WARNING 'notify_super_admin: no super admins found';
    RETURN NEW;
  END IF;

  v_subject := 'Yeni Yonetici Basvurusu: ' || NEW.applicant_name || ' (' || COALESCE(v_tenant_code, NEW.tenant_id::text) || ')';

  v_html := '<div>' || NEW.applicant_name || ' - ' || NEW.applicant_email || '</div>';

  PERFORM net.http_post(
    url     := 'https://api.resend.com/emails',
    headers := jsonb_build_object(
      'Authorization', 'Bearer ' || v_resend_key,
      'Content-Type',  'application/json'
    ),
    body    := jsonb_build_object(
      'from',    'VERA <vera@huguryildiz.com>',
      'to',      v_to_array,
      'subject', v_subject,
      'html',    v_html
    )
  );

  RETURN NEW;
END;
$$;


--
-- Name: rpc_admin_application_approve(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_application_approve(p_application_id uuid) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE
  v_uid uuid;
  v_app tenant_admin_applications%ROWTYPE;
  v_new_user_id uuid;
  v_tsl text;
BEGIN
  SELECT * INTO v_app FROM tenant_admin_applications WHERE id = p_application_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'application_not_found'; END IF;
  v_uid := public._assert_tenant_admin(v_app.tenant_id);
  IF v_app.status <> 'pending' THEN RAISE EXCEPTION 'application_not_pending'; END IF;

  SELECT id INTO v_new_user_id FROM auth.users
  WHERE lower(trim(email)) = lower(trim(v_app.applicant_email))
  LIMIT 1;

  IF v_new_user_id IS NULL THEN
    RAISE EXCEPTION 'auth_user_not_found';
  END IF;

  UPDATE tenant_admin_applications SET
    status = 'approved', reviewed_by = v_uid, reviewed_at = now(),
    encrypted_password = NULL, updated_at = now()
  WHERE id = p_application_id;

  VALUES (v_app.tenant_id, v_new_user_id, 'tenant_admin')
  ON CONFLICT DO NOTHING;

  VALUES (v_new_user_id, v_app.applicant_name)
  ON CONFLICT (user_id) DO NOTHING;

  SELECT COALESCE(
    NULLIF(
      concat_ws(' · ', NULLIF(trim(university), ''), NULLIF(trim(department), '')),
      ''
    ),
    short_label
  )
  INTO v_tsl
  FROM tenants
  WHERE id = v_app.tenant_id;

  PERFORM public._audit_log('admin', v_uid, 'application_approve', 'tenant_admin_application', p_application_id,
    format('Approved admin application for %s.', v_app.applicant_email), jsonb_build_object('tenant_id', v_app.tenant_id));

  PERFORM public._dispatch_application_notification(
    'application_approved',
    p_application_id,
    v_app.applicant_email,
    v_app.tenant_id,
    v_app.applicant_name,
    v_tsl
  );

  RETURN true;
END; $$;


--
-- Name: rpc_admin_application_cancel(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_application_cancel(p_application_id uuid) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_uid uuid; v_email text; v_app_email text;
BEGIN
  v_uid := public._get_auth_user_id();
  SELECT email INTO v_email FROM auth.users WHERE id = v_uid;
  SELECT applicant_email INTO v_app_email FROM tenant_admin_applications WHERE id = p_application_id;
  IF v_app_email IS NULL THEN RAISE EXCEPTION 'application_not_found'; END IF;
  IF lower(trim(v_email)) <> lower(trim(v_app_email)) THEN RAISE EXCEPTION 'forbidden' USING ERRCODE = 'P0403'; END IF;
  UPDATE tenant_admin_applications SET status = 'cancelled', updated_at = now() WHERE id = p_application_id AND status = 'pending';
  IF NOT FOUND THEN RAISE EXCEPTION 'application_not_pending'; END IF;
  PERFORM public._audit_log('admin', v_uid, 'application_cancel', 'tenant_admin_application', p_application_id, 'Application cancelled by applicant.', NULL);
  RETURN true;
END; $$;


