-- Name: rpc_admin_application_get_approval_payload(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_application_get_approval_payload(p_application_id uuid) RETURNS TABLE(tenant_id uuid, applicant_email text, applicant_name text, encrypted_password text)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE
  v_app tenant_admin_applications%ROWTYPE;
BEGIN
  SELECT * INTO v_app FROM tenant_admin_applications WHERE id = p_application_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'application_not_found'; END IF;
  IF v_app.status <> 'pending' THEN RAISE EXCEPTION 'application_not_pending'; END IF;

  PERFORM public._assert_tenant_admin(v_app.tenant_id);

  RETURN QUERY
  SELECT
    v_app.tenant_id,
    lower(trim(v_app.applicant_email)),
    v_app.applicant_name,
    v_app.encrypted_password;
END; $$;


--
-- Name: rpc_admin_application_get_mine(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_application_get_mine() RETURNS TABLE(id uuid, tenant_id uuid, applicant_email text, applicant_name text, status text, created_at timestamp with time zone, updated_at timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_uid uuid; v_email text;
BEGIN
  v_uid := public._get_auth_user_id();
  SELECT email INTO v_email FROM auth.users WHERE id = v_uid;
  RETURN QUERY SELECT a.id, a.tenant_id, a.applicant_email, a.applicant_name, a.status, a.created_at, a.updated_at
    FROM tenant_admin_applications a WHERE lower(trim(a.applicant_email)) = lower(trim(v_email)) ORDER BY a.created_at DESC;
END; $$;


