CREATE FUNCTION public.rpc_admin_application_list_pending(p_tenant_id uuid) RETURNS TABLE(id uuid, tenant_id uuid, applicant_email text, applicant_name text, university text, department text, status text, created_at timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
BEGIN
  PERFORM public._assert_tenant_admin(p_tenant_id);
  RETURN QUERY SELECT a.id, a.tenant_id, a.applicant_email, a.applicant_name, a.university, a.department, a.status, a.created_at
    FROM tenant_admin_applications a WHERE a.tenant_id = p_tenant_id AND a.status = 'pending' ORDER BY a.created_at ASC;
END; $$;


--
-- Name: rpc_admin_application_reject(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_application_reject(p_application_id uuid) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_uid uuid; v_app tenant_admin_applications%ROWTYPE; v_tsl text;
BEGIN
  SELECT * INTO v_app FROM tenant_admin_applications WHERE id = p_application_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'application_not_found'; END IF;
  v_uid := public._assert_tenant_admin(v_app.tenant_id);
  IF v_app.status <> 'pending' THEN RAISE EXCEPTION 'application_not_pending'; END IF;
  UPDATE tenant_admin_applications SET status = 'rejected', reviewed_by = v_uid, reviewed_at = now(), updated_at = now() WHERE id = p_application_id;
  SELECT COALESCE(
    NULLIF(
      concat_ws(' · ', NULLIF(trim(university), ''), NULLIF(trim(department), '')),
      ''
    ),
    short_label
  )
  INTO v_tsl
  FROM tenants
  WHERE id = v_app.tenant_id;
  PERFORM public._audit_log('admin', v_uid, 'application_reject', 'tenant_admin_application', p_application_id,
    format('Rejected admin application for %s.', v_app.applicant_email), jsonb_build_object('tenant_id', v_app.tenant_id));
  PERFORM public._dispatch_application_notification('application_rejected', p_application_id, v_app.applicant_email, v_app.tenant_id, v_app.applicant_name, v_tsl);
  RETURN true;
END; $$;


--
-- Name: rpc_admin_application_review_by_token(uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_application_review_by_token(p_application_id uuid, p_decision text) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE
  v_app tenant_admin_applications%ROWTYPE;
  v_new_user_id uuid;
  v_tsl text;
  v_decision text;
BEGIN
  v_decision := lower(trim(coalesce(p_decision, '')));
  IF v_decision NOT IN ('approve', 'reject') THEN
    RAISE EXCEPTION 'invalid_decision';
  END IF;

  SELECT * INTO v_app
  FROM tenant_admin_applications
  WHERE id = p_application_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'application_not_found';
  END IF;

  IF v_app.status <> 'pending' THEN
    RAISE EXCEPTION 'application_not_pending';
  END IF;

  SELECT short_label INTO v_tsl
  FROM tenants
  WHERE id = v_app.tenant_id;

  IF v_decision = 'approve' THEN
    -- Check if user already exists (e.g. re-approval or manual creation).
    SELECT id INTO v_new_user_id
    FROM auth.users
    WHERE lower(trim(email)) = lower(trim(v_app.applicant_email))
    LIMIT 1;

    -- Create auth.users entry if not exists.
    IF v_new_user_id IS NULL THEN
      IF v_app.encrypted_password IS NULL THEN
        RAISE EXCEPTION 'no_password_stored';
      END IF;

      v_new_user_id := gen_random_uuid();
        instance_id, id, aud, role, email, encrypted_password,
        email_confirmed_at, raw_app_meta_data, raw_user_meta_data,
        created_at, updated_at, confirmation_token, is_super_admin
      ) VALUES (
        '00000000-0000-0000-0000-000000000000', v_new_user_id, 'authenticated', 'authenticated',
        lower(trim(v_app.applicant_email)), v_app.encrypted_password,
        now(),
        '{"provider":"email","providers":["email"]}'::jsonb,
        jsonb_build_object('name', v_app.applicant_name),
        now(), now(), '', false
      );

      -- Create identity row (required by Supabase Auth).
        id, user_id, provider_id, identity_data, provider, last_sign_in_at, created_at, updated_at
      ) VALUES (
        v_new_user_id,
        v_new_user_id,
        lower(trim(v_app.applicant_email)),
        jsonb_build_object('sub', v_new_user_id::text, 'email', lower(trim(v_app.applicant_email))),
        'email',
        now(),
        now(),
        now()
      );
    END IF;

    UPDATE tenant_admin_applications
    SET
      status = 'approved',
      reviewed_by = NULL,
      reviewed_at = now(),
      encrypted_password = NULL,
      updated_at = now()
    WHERE id = p_application_id;

    VALUES (v_app.tenant_id, v_new_user_id, 'tenant_admin')
    ON CONFLICT DO NOTHING;

    VALUES (v_new_user_id, v_app.applicant_name)
    ON CONFLICT (user_id) DO NOTHING;

    PERFORM public._audit_log(
      'system',
      NULL,
      'application_approve_email_link',
      'tenant_admin_application',
      p_application_id,
      format('Approved admin application via email link for %s.', v_app.applicant_email),
      jsonb_build_object('tenant_id', v_app.tenant_id)
    );

    PERFORM public._dispatch_application_notification(
      'application_approved',
      p_application_id,
      v_app.applicant_email,
      v_app.tenant_id,
      v_app.applicant_name,
      v_tsl
    );

    RETURN true;
  END IF;

  UPDATE tenant_admin_applications
  SET
    status = 'rejected',
    reviewed_by = NULL,
    reviewed_at = now(),
    updated_at = now()
  WHERE id = p_application_id;

  PERFORM public._audit_log(
    'system',
    NULL,
    'application_reject_email_link',
    'tenant_admin_application',
    p_application_id,
    format('Rejected admin application via email link for %s.', v_app.applicant_email),
    jsonb_build_object('tenant_id', v_app.tenant_id)
  );

  PERFORM public._dispatch_application_notification(
    'application_rejected',
    p_application_id,
    v_app.applicant_email,
    v_app.tenant_id,
    v_app.applicant_name,
    v_tsl
  );

  RETURN true;
END;
$$;


--
-- Name: rpc_admin_application_submit(uuid, text, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_application_submit(p_tenant_id uuid, p_name text, p_university text DEFAULT ''::text, p_department text DEFAULT ''::text) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_uid uuid; v_email text; v_id uuid; v_tsl text; v_notify_email text;
BEGIN
  v_uid := public._get_auth_user_id();
  SELECT email INTO v_email FROM auth.users WHERE id = v_uid;
  v_email := lower(trim(COALESCE(v_email, '')));
  IF v_email = '' THEN RAISE EXCEPTION 'email_required'; END IF;
  IF trim(COALESCE(p_name,'')) = '' THEN RAISE EXCEPTION 'name_required'; END IF;
  IF NOT EXISTS (SELECT 1 FROM tenants WHERE id = p_tenant_id AND status = 'active') THEN
    RAISE EXCEPTION 'tenant_not_found';
  END IF;
  -- Prevent duplicate pending applications for same tenant+email.
  IF EXISTS (
    SELECT 1
    FROM tenant_admin_applications a
    WHERE a.tenant_id = p_tenant_id
      AND a.status = 'pending'
      AND lower(trim(a.applicant_email)) = v_email
  ) THEN
    RAISE EXCEPTION 'application_already_pending';
  END IF;

  VALUES (p_tenant_id, v_email, trim(p_name), COALESCE(trim(p_university),''), COALESCE(trim(p_department),''))
  RETURNING id INTO v_id;

  SELECT COALESCE(
    NULLIF(
      concat_ws(' · ', NULLIF(trim(university), ''), NULLIF(trim(department), '')),
      ''
    ),
    short_label
  )
  INTO v_tsl
  FROM tenants
  WHERE id = p_tenant_id;
  PERFORM public._audit_log('admin', v_uid, 'application_submit', 'tenant_admin_application', v_id,
    format('Application submitted by %s for tenant %s.', v_email, COALESCE(v_tsl, p_tenant_id::text)),
    jsonb_build_object('tenant_id', p_tenant_id));

  -- Notification targets: all global super admin emails.
  FOR v_notify_email IN
    SELECT lower(trim(u.email))
    FROM tenant_admin_memberships tam
    JOIN auth.users u ON u.id = tam.user_id
    WHERE tam.role = 'super_admin'
      AND tam.tenant_id IS NULL
      AND u.email IS NOT NULL
      AND trim(u.email) <> ''
    ORDER BY tam.created_at ASC
  LOOP
    PERFORM public._dispatch_application_notification(
      'application_submitted',
      v_id,
      v_notify_email,
      p_tenant_id,
      trim(p_name),
      v_tsl
    );
  END LOOP;

  RETURN v_id;
END; $$;


--
-- Name: rpc_admin_application_submit(uuid, text, text, text, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_application_submit(p_tenant_id uuid, p_email text, p_password text, p_name text, p_university text DEFAULT ''::text, p_department text DEFAULT ''::text) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_id uuid; v_tsl text; v_hash text; v_notify_email text; v_email text;
BEGIN
  v_email := lower(trim(COALESCE(p_email, '')));
  -- Validate
  IF v_email = '' THEN RAISE EXCEPTION 'email_required'; END IF;
  IF trim(COALESCE(p_name,'')) = '' THEN RAISE EXCEPTION 'name_required'; END IF;
  IF length(COALESCE(p_password,'')) < 10 THEN RAISE EXCEPTION 'password_too_short'; END IF;
  IF NOT EXISTS (SELECT 1 FROM tenants WHERE id = p_tenant_id AND status = 'active') THEN
    RAISE EXCEPTION 'tenant_not_found';
  END IF;
  -- Check for existing auth user with same email
  IF EXISTS (SELECT 1 FROM auth.users WHERE lower(trim(email)) = v_email) THEN
    RAISE EXCEPTION 'email_already_registered';
  END IF;
  -- Prevent duplicate pending applications for same tenant+email.
  IF EXISTS (
    SELECT 1
    FROM tenant_admin_applications a
    WHERE a.tenant_id = p_tenant_id
      AND a.status = 'pending'
      AND lower(trim(a.applicant_email)) = v_email
  ) THEN
    RAISE EXCEPTION 'application_already_pending';
  END IF;

  v_hash := crypt(p_password, gen_salt('bf'));
  VALUES (p_tenant_id, v_email, trim(p_name), COALESCE(trim(p_university),''), COALESCE(trim(p_department),''), v_hash)
  RETURNING id INTO v_id;

  SELECT COALESCE(
    NULLIF(
      concat_ws(' · ', NULLIF(trim(university), ''), NULLIF(trim(department), '')),
      ''
    ),
    short_label
  )
  INTO v_tsl
  FROM tenants
  WHERE id = p_tenant_id;
  PERFORM public._audit_log('system', NULL, 'application_submit', 'tenant_admin_application', v_id,
    format('Application submitted by %s for tenant %s.', v_email, COALESCE(v_tsl, p_tenant_id::text)),
    jsonb_build_object('tenant_id', p_tenant_id));

  -- Notification targets: all global super admin emails.
  FOR v_notify_email IN
    SELECT lower(trim(u.email))
    FROM tenant_admin_memberships tam
    JOIN auth.users u ON u.id = tam.user_id
    WHERE tam.role = 'super_admin'
      AND tam.tenant_id IS NULL
      AND u.email IS NOT NULL
      AND trim(u.email) <> ''
    ORDER BY tam.created_at ASC
  LOOP
    PERFORM public._dispatch_application_notification(
      'application_submitted',
      v_id,
      v_notify_email,
      p_tenant_id,
      trim(p_name),
      v_tsl
    );
  END LOOP;

  RETURN v_id;
END; $$;


--
-- Name: rpc_admin_audit_list(uuid, timestamp with time zone, timestamp with time zone, text[], text[], text, integer, integer, integer, integer, timestamp with time zone, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_audit_list(p_tenant_id uuid, p_start_at timestamp with time zone DEFAULT NULL::timestamp with time zone, p_end_at timestamp with time zone DEFAULT NULL::timestamp with time zone, p_actor_types text[] DEFAULT NULL::text[], p_actions text[] DEFAULT NULL::text[], p_search text DEFAULT NULL::text, p_search_day integer DEFAULT NULL::integer, p_search_month integer DEFAULT NULL::integer, p_search_year integer DEFAULT NULL::integer, p_limit integer DEFAULT 100, p_before_at timestamp with time zone DEFAULT NULL::timestamp with time zone, p_before_id uuid DEFAULT NULL::uuid) RETURNS TABLE(id uuid, created_at timestamp with time zone, actor_type text, actor_id uuid, action text, entity_type text, entity_id uuid, message text, metadata jsonb)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_lim integer; v_at text[]; v_ac text[]; v_s text;
BEGIN
  PERFORM public._assert_tenant_admin(p_tenant_id);
  v_lim := GREATEST(1, LEAST(COALESCE(p_limit, 100), 500));
  v_at := array_remove(p_actor_types, '');
  v_ac := array_remove(p_actions, '');
  IF v_at IS NOT NULL AND array_length(v_at, 1) IS NULL THEN v_at := NULL; END IF;
  IF v_ac IS NOT NULL AND array_length(v_ac, 1) IS NULL THEN v_ac := NULL; END IF;
  v_s := NULLIF(btrim(p_search), '');
  RETURN QUERY SELECT a.id, a.created_at, a.actor_type, a.actor_id, a.action,
    a.entity_type, a.entity_id, a.message, a.metadata
  FROM audit_logs a
  WHERE (a.tenant_id = p_tenant_id OR a.tenant_id IS NULL)
    AND (p_start_at IS NULL OR a.created_at >= p_start_at)
    AND (p_end_at IS NULL OR a.created_at <= p_end_at)
    AND (v_at IS NULL OR a.actor_type = ANY(v_at))
    AND (v_ac IS NULL OR a.action = ANY(v_ac))
    AND (v_s IS NULL OR a.message ILIKE '%'||v_s||'%' OR a.entity_type ILIKE '%'||v_s||'%'
      OR a.action ILIKE '%'||v_s||'%' OR a.metadata::text ILIKE '%'||v_s||'%'
      OR (p_search_day IS NOT NULL AND p_search_month IS NOT NULL
          AND EXTRACT(DAY FROM a.created_at) = p_search_day AND EXTRACT(MONTH FROM a.created_at) = p_search_month
          AND (p_search_year IS NULL OR EXTRACT(YEAR FROM a.created_at) = p_search_year))
      OR (p_search_day IS NULL AND p_search_month IS NOT NULL
          AND EXTRACT(MONTH FROM a.created_at) = p_search_month
          AND (p_search_year IS NULL OR EXTRACT(YEAR FROM a.created_at) = p_search_year)))
    AND (p_before_at IS NULL OR a.created_at < p_before_at
      OR (a.created_at = p_before_at AND (p_before_id IS NULL OR a.id < p_before_id)))
  ORDER BY a.created_at DESC, a.id DESC LIMIT v_lim;
END; $$;


--
-- Name: rpc_admin_auth_get_session(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_auth_get_session() RETURNS TABLE(user_id uuid, user_email text, tenant_id uuid, tenant_code text, tenant_short_label text, role text)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_uid uuid; v_is_super boolean; v_email text;
BEGIN
  v_uid := public._get_auth_user_id();
  SELECT u.email INTO v_email FROM auth.users u WHERE u.id = v_uid;

  SELECT EXISTS (
    SELECT 1 FROM tenant_admin_memberships tam
    WHERE tam.user_id = v_uid AND tam.role = 'super_admin' AND tam.tenant_id IS NULL
  ) INTO v_is_super;

  IF v_is_super THEN
    RETURN QUERY SELECT v_uid, v_email::text, NULL::uuid, NULL::text, NULL::text, 'super_admin'::text;
    RETURN QUERY SELECT v_uid, v_email::text, t.id, t.code, t.short_label, 'super_admin'::text
      FROM tenants t WHERE t.status = 'active' ORDER BY t.code;
  ELSE
    RETURN QUERY SELECT tam.user_id, v_email::text, tam.tenant_id, t.code, t.short_label, tam.role
      FROM tenant_admin_memberships tam
      LEFT JOIN tenants t ON t.id = tam.tenant_id
      WHERE tam.user_id = v_uid;
  END IF;
END; $$;


--
-- Name: rpc_admin_auth_user_id_by_email(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_auth_user_id_by_email(p_email text) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE
  v_uid uuid;
BEGIN
  IF p_email IS NULL OR trim(p_email) = '' THEN
    RETURN NULL;
  END IF;

  SELECT u.id
    INTO v_uid
  FROM auth.users u
  WHERE lower(trim(u.email)) = lower(trim(p_email))
  LIMIT 1;

  RETURN v_uid;
END; $$;


--
-- Name: rpc_admin_bootstrap_backup_password(text, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_bootstrap_backup_password(p_new_password text, p_admin_password text, p_rpc_secret text DEFAULT ''::text) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_hash text;
BEGIN
  IF NOT public._verify_admin_password(p_admin_password, p_rpc_secret) THEN
    RAISE EXCEPTION 'unauthorized' USING ERRCODE = 'P0401'; END IF;
  SELECT value INTO v_hash FROM settings WHERE key = 'backup_password_hash' AND tenant_id IS NULL;
  IF v_hash IS NOT NULL AND v_hash <> '' THEN RAISE EXCEPTION 'already_initialized'; END IF;
  ON CONFLICT (key) WHERE tenant_id IS NULL DO UPDATE SET value = EXCLUDED.value, updated_at = now();
  PERFORM public._audit_log('admin', null::uuid, 'backup_password_change', 'settings', null::uuid,
    'Admin initialized backup password.', null);
  RETURN true;
END; $$;


