    'Admin changed admin password.', null);
  RETURN QUERY SELECT true;
END; $$;


--
-- Name: rpc_admin_change_backup_password(text, text, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_change_backup_password(p_current_password text, p_new_password text, p_admin_password text, p_rpc_secret text DEFAULT ''::text) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
