CREATE FUNCTION public.rpc_admin_change_delete_password(p_current_password text, p_new_password text, p_admin_password text, p_rpc_secret text DEFAULT ''::text) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
