--
-- Name: rpc_admin_change_password(text, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_change_password(p_current_password text, p_new_password text, p_rpc_secret text DEFAULT ''::text) RETURNS TABLE(ok boolean)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_hash text;
BEGIN
  PERFORM public._verify_rpc_secret(p_rpc_secret);
  SELECT value INTO v_hash FROM settings WHERE key = 'admin_password_hash' AND tenant_id IS NULL;
  IF v_hash IS NULL OR v_hash = '' THEN RAISE EXCEPTION 'admin_password_hash_missing'; END IF;
  IF crypt(p_current_password, v_hash) <> v_hash THEN RAISE EXCEPTION 'incorrect_password'; END IF;
  ON CONFLICT (key) WHERE tenant_id IS NULL DO UPDATE SET value = EXCLUDED.value, updated_at = now();
  PERFORM public._audit_log('admin', null::uuid, 'admin_password_change', 'settings', null::uuid,
    'Admin changed admin password.', null);
  RETURN QUERY SELECT true;
END; $$;


--
-- Name: rpc_admin_create_juror(text, text, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_create_juror(p_juror_name text, p_juror_inst text, p_admin_password text, p_rpc_secret text DEFAULT ''::text) RETURNS TABLE(juror_id uuid, juror_name text, juror_inst text)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
#variable_conflict use_column
DECLARE v_nn text; v_ni text; v_id uuid; v_name text; v_inst text; v_csem uuid; v_tid uuid; v_pin text; v_hash text;
BEGIN
  IF NOT public._verify_admin_password(p_admin_password, p_rpc_secret) THEN RAISE EXCEPTION 'unauthorized' USING ERRCODE = 'P0401'; END IF;
  v_nn := lower(regexp_replace(trim(coalesce(p_juror_name,'')), '\\s+', ' ', 'g'));
  v_ni := lower(regexp_replace(trim(coalesce(p_juror_inst,'')), '\\s+', ' ', 'g'));
  SELECT j.id, j.juror_name, j.juror_inst INTO v_id, v_name, v_inst FROM jurors j
  WHERE lower(regexp_replace(trim(coalesce(j.juror_name,'')), '\\s+', ' ', 'g')) = v_nn
    AND lower(regexp_replace(trim(coalesce(j.juror_inst,'')), '\\s+', ' ', 'g')) = v_ni LIMIT 1;
  IF v_id IS NOT NULL THEN RAISE EXCEPTION 'juror_exists'; END IF;
  RETURNING jurors.id, jurors.juror_name, jurors.juror_inst INTO v_id, v_name, v_inst;
  SELECT id, tenant_id INTO v_csem, v_tid FROM semesters WHERE is_current = true ORDER BY updated_at DESC LIMIT 1;
  IF v_csem IS NOT NULL THEN
    v_pin := lpad((('x' || encode(gen_random_bytes(2), 'hex'))::bit(16)::int % 10000)::text, 4, '0');
    v_hash := crypt(v_pin, gen_salt('bf'));
    VALUES (v_id, v_csem, COALESCE(v_tid, gen_random_uuid()), v_hash) ON CONFLICT (juror_id, semester_id) DO NOTHING;
    SELECT p.semester_id, COALESCE(v_tid, gen_random_uuid()), p.id, v_id, s.poster_date
    FROM projects p JOIN semesters s ON s.id = p.semester_id WHERE p.semester_id = v_csem
    ON CONFLICT ON CONSTRAINT scores_unique_eval DO NOTHING;
  END IF;
  PERFORM public._audit_log('admin', null::uuid, 'juror_create', 'juror', v_id,
    format('Admin created juror %s%s.', COALESCE(v_name,''), CASE WHEN COALESCE(NULLIF(trim(v_inst),''),'') = '' THEN '' ELSE format(' (%s)', v_inst) END), NULL);
  RETURN QUERY SELECT v_id, v_name, v_inst;
END; $$;


--
-- Name: rpc_admin_create_project(uuid, integer, text, text, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_create_project(p_semester_id uuid, p_group_no integer, p_project_title text, p_group_students text, p_admin_password text, p_rpc_secret text DEFAULT ''::text) RETURNS TABLE(project_id uuid)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_id uuid; v_tid uuid; v_sn text; v_lk boolean := false;
BEGIN
  IF NOT public._verify_admin_password(p_admin_password, p_rpc_secret) THEN RAISE EXCEPTION 'unauthorized' USING ERRCODE = 'P0401'; END IF;
  SELECT semester_name, COALESCE(is_locked,false), tenant_id INTO v_sn, v_lk, v_tid FROM semesters WHERE id = p_semester_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'semester_not_found'; END IF;
  IF v_lk THEN RAISE EXCEPTION 'semester_locked'; END IF;
  IF EXISTS (SELECT 1 FROM projects WHERE semester_id = p_semester_id AND group_no = p_group_no) THEN RAISE EXCEPTION 'project_group_exists'; END IF;
  VALUES (p_semester_id, v_tid, p_group_no, p_project_title, p_group_students) RETURNING id INTO v_id;
  SELECT jsa.semester_id, v_tid, v_id, jsa.juror_id, sem.poster_date
  FROM juror_semester_auth jsa JOIN semesters sem ON sem.id = jsa.semester_id WHERE jsa.semester_id = p_semester_id
  ON CONFLICT ON CONSTRAINT scores_unique_eval DO NOTHING;
  PERFORM public._audit_log('admin', null::uuid, 'project_create', 'project', v_id,
    format('Admin created project Group %s — %s (%s).', p_group_no, p_project_title, COALESCE(v_sn, p_semester_id::text)),
    jsonb_build_object('semester_id', p_semester_id, 'group_no', p_group_no, 'semester_name', v_sn));
  RETURN QUERY SELECT v_id;
END; $$;


--
-- Name: rpc_admin_create_semester(text, date, jsonb, jsonb, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_create_semester(p_semester_name text, p_poster_date date, p_criteria_template jsonb DEFAULT NULL::jsonb, p_mudek_template jsonb DEFAULT NULL::jsonb, p_admin_password text DEFAULT ''::text, p_rpc_secret text DEFAULT ''::text) RETURNS TABLE(id uuid, semester_name text, is_current boolean, poster_date date, criteria_template jsonb, mudek_template jsonb)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
#variable_conflict use_column
DECLARE v_id uuid; v_sn text; v_cur boolean; v_pd date; v_ct jsonb; v_mt jsonb;
BEGIN
  IF NOT public._verify_admin_password(p_admin_password, p_rpc_secret) THEN RAISE EXCEPTION 'unauthorized' USING ERRCODE = 'P0401'; END IF;
  v_sn := trim(p_semester_name);
  IF v_sn IS NULL OR v_sn = '' THEN RAISE EXCEPTION 'semester_name_required'; END IF;
  IF EXISTS (SELECT 1 FROM semesters s WHERE lower(trim(s.semester_name)) = lower(v_sn)) THEN RAISE EXCEPTION 'semester_name_exists'; END IF;
  VALUES (v_sn, false, p_poster_date, COALESCE(p_criteria_template,'[]'::jsonb), COALESCE(p_mudek_template,'[]'::jsonb))
  RETURNING semesters.id, semesters.semester_name, semesters.is_current, semesters.poster_date, semesters.criteria_template, semesters.mudek_template
    INTO v_id, v_sn, v_cur, v_pd, v_ct, v_mt;
  PERFORM public._audit_log('admin', null::uuid, 'semester_create', 'semester', v_id,
    format('Admin created semester %s.', v_sn), jsonb_build_object('poster_date', v_pd));
  RETURN QUERY SELECT v_id, v_sn, v_cur, v_pd, v_ct, v_mt;
END; $$;


--
-- Name: rpc_admin_delete_counts(text, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_delete_counts(p_type text, p_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_p bigint:=0; v_s bigint:=0; v_ja bigint:=0; v_sem bigint:=0;
BEGIN
  IF auth.uid() IS NULL THEN RAISE EXCEPTION 'unauthorized' USING ERRCODE = 'P0401'; END IF;
  IF NOT EXISTS (SELECT 1 FROM tenant_admin_memberships WHERE user_id = auth.uid()) THEN
    RAISE EXCEPTION 'unauthorized' USING ERRCODE = 'P0401'; END IF;
  IF p_type = 'semester' THEN
    SELECT COUNT(*) INTO v_p FROM projects WHERE semester_id = p_id;
    SELECT COUNT(*) INTO v_s FROM scores WHERE semester_id = p_id
      AND (final_submitted_at IS NOT NULL OR (criteria_scores IS NOT NULL AND criteria_scores <> '{}'::jsonb));
    SELECT COUNT(*) INTO v_ja FROM juror_semester_auth WHERE semester_id = p_id;
    RETURN jsonb_build_object('projects', v_p, 'scores', v_s, 'juror_auths', v_ja);
  ELSIF p_type = 'project' THEN
    SELECT COUNT(*) INTO v_s FROM scores WHERE project_id = p_id
      AND (final_submitted_at IS NOT NULL OR (criteria_scores IS NOT NULL AND criteria_scores <> '{}'::jsonb));
    RETURN jsonb_build_object('scores', v_s);
  ELSIF p_type = 'juror' THEN
    SELECT COUNT(DISTINCT semester_id) INTO v_sem FROM scores WHERE juror_id = p_id AND final_submitted_at IS NOT NULL;
    SELECT COUNT(*) INTO v_s FROM scores WHERE juror_id = p_id AND final_submitted_at IS NOT NULL;
    SELECT COUNT(*) INTO v_ja FROM juror_semester_auth WHERE juror_id = p_id;
    RETURN jsonb_build_object('scores', v_s, 'juror_auths', v_ja, 'active_semesters', v_sem);
  ELSE RAISE EXCEPTION 'unsupported_type'; END IF;
END; $$;


