--
-- Name: rpc_admin_entry_token_generate(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_entry_token_generate(p_semester_id uuid) RETURNS TABLE(raw_token text)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_raw text; v_hash text; v_sn text;
BEGIN
  PERFORM public._assert_semester_access(p_semester_id);
  v_raw := encode(gen_random_bytes(24), 'base64');
  v_hash := encode(extensions.digest(v_raw, 'sha256'), 'hex');
  UPDATE semesters SET entry_token_hash = v_hash, entry_token_enabled = true,
    entry_token_created_at = now(), entry_token_expires_at = null, updated_at = now()
  WHERE id = p_semester_id RETURNING semester_name INTO v_sn;
  IF NOT FOUND THEN RAISE EXCEPTION 'semester_not_found'; END IF;
  PERFORM public._audit_log('admin', auth.uid(), 'entry_token_generate', 'semester', p_semester_id,
    format('Jury entry token generated (%s)', coalesce(v_sn, p_semester_id::text)),
    jsonb_build_object('semester_id', p_semester_id, 'semester_name', v_sn));
  RETURN QUERY SELECT v_raw;
END; $$;


--
-- Name: rpc_admin_entry_token_revoke(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_entry_token_revoke(p_semester_id uuid) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_sn text;
BEGIN
  PERFORM public._assert_semester_access(p_semester_id);
  UPDATE semesters SET entry_token_enabled = false, updated_at = now()
  WHERE id = p_semester_id RETURNING semester_name INTO v_sn;
  IF NOT FOUND THEN RAISE EXCEPTION 'semester_not_found'; END IF;
  PERFORM public._audit_log('admin', auth.uid(), 'entry_token_revoke', 'semester', p_semester_id,
    format('Jury entry token revoked (%s)', coalesce(v_sn, p_semester_id::text)),
    jsonb_build_object('semester_id', p_semester_id));
  RETURN true;
END; $$;


--
-- Name: rpc_admin_entry_token_status(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_entry_token_status(p_semester_id uuid) RETURNS TABLE(enabled boolean, created_at timestamp with time zone, expires_at timestamp with time zone, has_token boolean)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_sem semesters%ROWTYPE;
BEGIN
  PERFORM public._assert_semester_access(p_semester_id);
  SELECT * INTO v_sem FROM semesters WHERE id = p_semester_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'semester_not_found'; END IF;
  RETURN QUERY SELECT v_sem.entry_token_enabled, v_sem.entry_token_created_at,
    v_sem.entry_token_expires_at, (v_sem.entry_token_hash IS NOT NULL);
END; $$;


--
-- Name: rpc_admin_export_full(uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_export_full(p_tenant_id uuid, p_backup_password text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_payload jsonb;
BEGIN
  PERFORM public._assert_tenant_admin(p_tenant_id);
  PERFORM public._assert_backup_password(p_backup_password);
  v_payload := jsonb_build_object(
    'exported_at', now(), 'schema_version', 2, 'tenant_id', p_tenant_id,
    'tenant', (SELECT row_to_json(t) FROM (
      SELECT id, code, short_label, university, department, status FROM tenants WHERE id = p_tenant_id) t),
    'semesters', COALESCE((SELECT jsonb_agg(row_to_json(s)) FROM (
      SELECT id, tenant_id, semester_name, is_current, is_locked, poster_date,
        criteria_template, mudek_template, created_at, updated_at
      FROM semesters WHERE tenant_id = p_tenant_id) s), '[]'::jsonb),
    'jurors', COALESCE((SELECT jsonb_agg(DISTINCT jsonb_build_object(
      'id',j.id,'juror_name',j.juror_name,'juror_inst',j.juror_inst,
      'created_at',j.created_at,'updated_at',j.updated_at))
      FROM jurors j WHERE EXISTS (
        SELECT 1 FROM juror_semester_auth jsa WHERE jsa.juror_id = j.id AND jsa.tenant_id = p_tenant_id
      )), '[]'::jsonb),
    'projects', COALESCE((SELECT jsonb_agg(row_to_json(p)) FROM projects p WHERE p.tenant_id = p_tenant_id), '[]'::jsonb),
    'scores', COALESCE((SELECT jsonb_agg(row_to_json(sc)) FROM scores sc WHERE sc.tenant_id = p_tenant_id), '[]'::jsonb),
    'juror_semester_auth', COALESCE((SELECT jsonb_agg(jsonb_build_object(
      'id',a.id,'juror_id',a.juror_id,'semester_id',a.semester_id,'tenant_id',a.tenant_id,
      'created_at',a.created_at,'last_seen_at',a.last_seen_at,'failed_attempts',a.failed_attempts,
      'locked_until',a.locked_until,'edit_enabled',a.edit_enabled,'pin_reveal_pending',a.pin_reveal_pending))
      FROM juror_semester_auth a WHERE a.tenant_id = p_tenant_id), '[]'::jsonb));
  PERFORM public._audit_log('admin', auth.uid(), 'db_export', 'settings', null::uuid,
    'Admin exported database backup.', jsonb_build_object('tenant_id', p_tenant_id));
  RETURN v_payload;
END; $$;


--
-- Name: rpc_admin_force_close_juror_edit_mode(uuid, uuid, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_force_close_juror_edit_mode(p_semester_id uuid, p_juror_id uuid, p_admin_password text, p_rpc_secret text DEFAULT ''::text) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_name text; v_sn text;
BEGIN
  IF NOT public._verify_admin_password(p_admin_password, p_rpc_secret) THEN RAISE EXCEPTION 'unauthorized' USING ERRCODE = 'P0401'; END IF;
  IF NOT EXISTS (SELECT 1 FROM semesters s WHERE s.id = p_semester_id) THEN RAISE EXCEPTION 'semester_not_found'; END IF;
  UPDATE juror_semester_auth SET edit_enabled = false WHERE juror_id = p_juror_id AND semester_id = p_semester_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'no_pin'; END IF;
  SELECT juror_name INTO v_name FROM jurors WHERE id = p_juror_id;
  SELECT semester_name INTO v_sn FROM semesters WHERE id = p_semester_id;
  PERFORM public._audit_log('admin', null::uuid, 'admin_juror_edit_force_close', 'juror', p_juror_id,
    format('Admin force-closed edit mode for Juror %s (%s).', COALESCE(v_name, p_juror_id::text), COALESCE(v_sn, p_semester_id::text)),
    jsonb_build_object('semester_id', p_semester_id, 'enabled', false));
  RETURN true;
END; $$;


--
-- Name: rpc_admin_full_export(text, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_full_export(p_backup_password text, p_admin_password text, p_rpc_secret text DEFAULT ''::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_payload jsonb;
BEGIN
  IF NOT public._verify_admin_password(p_admin_password, p_rpc_secret) THEN
    RAISE EXCEPTION 'unauthorized' USING ERRCODE = 'P0401'; END IF;
  PERFORM public._assert_backup_password(p_backup_password);
  v_payload := jsonb_build_object(
    'exported_at', now(), 'schema_version', 2,
    'semesters', COALESCE((SELECT jsonb_agg(jsonb_build_object(
      'id',s.id,'tenant_id',s.tenant_id,'semester_name',s.semester_name,'is_current',s.is_current,
      'is_locked',s.is_locked,'poster_date',s.poster_date,'criteria_template',s.criteria_template,
      'mudek_template',s.mudek_template,'created_at',s.created_at,'updated_at',s.updated_at))
      FROM semesters s), '[]'::jsonb),
    'jurors', COALESCE((SELECT jsonb_agg(jsonb_build_object(
      'id',j.id,'juror_name',j.juror_name,'juror_inst',j.juror_inst,
      'created_at',j.created_at,'updated_at',j.updated_at)) FROM jurors j), '[]'::jsonb),
    'projects', COALESCE((SELECT jsonb_agg(row_to_json(p)) FROM projects p), '[]'::jsonb),
    'scores', COALESCE((SELECT jsonb_agg(row_to_json(sc)) FROM scores sc), '[]'::jsonb),
    'juror_semester_auth', COALESCE((SELECT jsonb_agg(jsonb_build_object(
      'id',a.id,'juror_id',a.juror_id,'semester_id',a.semester_id,'tenant_id',a.tenant_id,
      'created_at',a.created_at,'last_seen_at',a.last_seen_at,'failed_attempts',a.failed_attempts,
      'locked_until',a.locked_until,'edit_enabled',a.edit_enabled,'pin_reveal_pending',a.pin_reveal_pending))
      FROM juror_semester_auth a), '[]'::jsonb));
  PERFORM public._audit_log('admin', null::uuid, 'db_export', 'settings', null::uuid,
    'Admin exported database backup.', null);
  RETURN v_payload;
END; $$;


--
-- Name: rpc_admin_full_import(text, text, jsonb, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_full_import(p_backup_password text, p_admin_password text, p_data jsonb, p_rpc_secret text DEFAULT ''::text) RETURNS text
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE r jsonb; v_tid uuid;
BEGIN
  IF NOT public._verify_admin_password(p_admin_password, p_rpc_secret) THEN
    RAISE EXCEPTION 'unauthorized' USING ERRCODE = 'P0401'; END IF;
  PERFORM public._assert_backup_password(p_backup_password);
  SELECT id INTO v_tid FROM tenants WHERE status = 'active' ORDER BY created_at LIMIT 1;
  IF v_tid IS NULL THEN INSERT INTO tenants (code, short_label) VALUES ('default','Default') RETURNING id INTO v_tid; END IF;
  -- 1. Semesters
  FOR r IN SELECT * FROM jsonb_array_elements(COALESCE(p_data->'semesters','[]'::jsonb)) LOOP
    VALUES ((r->>'id')::uuid, COALESCE((r->>'tenant_id')::uuid, v_tid),
      COALESCE(r->>'semester_name', r->>'name'),
      COALESCE((r->>'is_current')::boolean, (r->>'is_active')::boolean, false),
      COALESCE((r->>'is_locked')::boolean, false), (r->>'poster_date')::date,
      COALESCE((r->>'created_at')::timestamptz, now()), COALESCE((r->>'updated_at')::timestamptz, now()))
    ON CONFLICT (id) DO UPDATE SET semester_name = EXCLUDED.semester_name, is_current = EXCLUDED.is_current,
      is_locked = EXCLUDED.is_locked, poster_date = EXCLUDED.poster_date, updated_at = EXCLUDED.updated_at;
  END LOOP;
  -- 2. Jurors
  FOR r IN SELECT * FROM jsonb_array_elements(COALESCE(p_data->'jurors','[]'::jsonb)) LOOP
      COALESCE((r->>'created_at')::timestamptz, now()), COALESCE((r->>'updated_at')::timestamptz, now()))
    ON CONFLICT (id) DO UPDATE SET juror_name = EXCLUDED.juror_name, juror_inst = EXCLUDED.juror_inst, updated_at = EXCLUDED.updated_at;
  END LOOP;
  -- 3. Juror semester auth
  FOR r IN SELECT * FROM jsonb_array_elements(COALESCE(p_data->'juror_semester_auth','[]'::jsonb)) LOOP
      pin_plain_once, created_at, failed_attempts, locked_until, last_seen_at, edit_enabled)
    VALUES ((r->>'id')::uuid, (r->>'juror_id')::uuid, (r->>'semester_id')::uuid,
      COALESCE((r->>'tenant_id')::uuid, v_tid), COALESCE(r->>'pin_hash', crypt('0000', gen_salt('bf'))),
      COALESCE((r->>'pin_reveal_pending')::boolean, false), r->>'pin_plain_once',
      COALESCE((r->>'created_at')::timestamptz, now()), COALESCE((r->>'failed_attempts')::integer, 0),
      (r->>'locked_until')::timestamptz, (r->>'last_seen_at')::timestamptz,
      COALESCE((r->>'edit_enabled')::boolean, false))
    ON CONFLICT (juror_id, semester_id) DO UPDATE SET pin_hash = EXCLUDED.pin_hash,
      pin_reveal_pending = EXCLUDED.pin_reveal_pending, pin_plain_once = EXCLUDED.pin_plain_once,
      failed_attempts = EXCLUDED.failed_attempts, locked_until = EXCLUDED.locked_until,
      last_seen_at = EXCLUDED.last_seen_at, edit_enabled = EXCLUDED.edit_enabled;
  END LOOP;
  -- 4. Projects
  FOR r IN SELECT * FROM jsonb_array_elements(COALESCE(p_data->'projects','[]'::jsonb)) LOOP
    VALUES ((r->>'id')::uuid, (r->>'semester_id')::uuid, COALESCE((r->>'tenant_id')::uuid, v_tid),
      (r->>'group_no')::integer, r->>'project_title', COALESCE(r->>'group_students',''),
      COALESCE((r->>'created_at')::timestamptz, now()), COALESCE((r->>'updated_at')::timestamptz, now()))
    ON CONFLICT (id) DO UPDATE SET semester_id = EXCLUDED.semester_id, group_no = EXCLUDED.group_no,
      project_title = EXCLUDED.project_title, group_students = EXCLUDED.group_students, updated_at = EXCLUDED.updated_at;
  END LOOP;
  -- 5. Scores
  FOR r IN SELECT * FROM jsonb_array_elements(COALESCE(p_data->'scores','[]'::jsonb)) LOOP
      criteria_scores, total, comment, final_submitted_at, created_at, updated_at)
    VALUES ((r->>'id')::uuid, (r->>'semester_id')::uuid, (r->>'project_id')::uuid, (r->>'juror_id')::uuid,
      COALESCE((r->>'tenant_id')::uuid, v_tid), (r->>'poster_date')::date,
      COALESCE(r->'criteria_scores', CASE
        WHEN (r->>'technical') IS NOT NULL OR (r->>'written') IS NOT NULL
             OR (r->>'oral') IS NOT NULL OR (r->>'teamwork') IS NOT NULL
        THEN jsonb_strip_nulls(jsonb_build_object('technical',(r->>'technical')::integer,
          'design',(r->>'written')::integer,'delivery',(r->>'oral')::integer,'teamwork',(r->>'teamwork')::integer))
        ELSE NULL END),
      (r->>'total')::integer, r->>'comment', (r->>'final_submitted_at')::timestamptz,
      COALESCE((r->>'created_at')::timestamptz, now()), COALESCE((r->>'updated_at')::timestamptz, now()))
    ON CONFLICT (id) DO UPDATE SET poster_date = EXCLUDED.poster_date, criteria_scores = EXCLUDED.criteria_scores,
      total = EXCLUDED.total, comment = EXCLUDED.comment, final_submitted_at = EXCLUDED.final_submitted_at,
      updated_at = EXCLUDED.updated_at;
  END LOOP;
  PERFORM public._audit_log('admin', null::uuid, 'db_import', 'settings', null::uuid,
    'Admin restored database from backup.', null);
  RETURN 'ok';
END; $$;


--
-- Name: rpc_admin_generate_entry_token(uuid, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_generate_entry_token(p_semester_id uuid, p_admin_password text, p_rpc_secret text DEFAULT ''::text) RETURNS TABLE(raw_token text)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_raw text; v_hash text; v_sn text;
BEGIN
  IF NOT public._verify_admin_password(p_admin_password, p_rpc_secret) THEN
    RAISE EXCEPTION 'unauthorized' USING ERRCODE = 'P0401'; END IF;
  v_raw := encode(gen_random_bytes(24), 'base64');
  v_hash := encode(extensions.digest(v_raw, 'sha256'), 'hex');
  UPDATE semesters SET entry_token_hash = v_hash, entry_token_enabled = true,
    entry_token_created_at = now(), entry_token_expires_at = null, updated_at = now()
  WHERE id = p_semester_id RETURNING semester_name INTO v_sn;
  IF NOT FOUND THEN RAISE EXCEPTION 'semester_not_found'; END IF;
  PERFORM public._audit_log('admin', null::uuid, 'entry_token_generate', 'semester', p_semester_id,
    format('Jury entry token generated (%s)', coalesce(v_sn, p_semester_id::text)),
    jsonb_build_object('semester_id', p_semester_id, 'semester_name', v_sn));
  RETURN QUERY SELECT v_raw;
END; $$;


--
-- Name: rpc_admin_get_entry_token_status(uuid, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_get_entry_token_status(p_semester_id uuid, p_admin_password text, p_rpc_secret text DEFAULT ''::text) RETURNS TABLE(enabled boolean, created_at timestamp with time zone, expires_at timestamp with time zone, has_token boolean)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_sem semesters%ROWTYPE;
BEGIN
  IF NOT public._verify_admin_password(p_admin_password, p_rpc_secret) THEN
    RAISE EXCEPTION 'unauthorized' USING ERRCODE = 'P0401'; END IF;
  SELECT * INTO v_sem FROM semesters WHERE id = p_semester_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'semester_not_found'; END IF;
  RETURN QUERY SELECT v_sem.entry_token_enabled, v_sem.entry_token_created_at,
    v_sem.entry_token_expires_at, (v_sem.entry_token_hash IS NOT NULL);
END; $$;


--
-- Name: rpc_admin_get_scores(uuid, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_get_scores(p_semester_id uuid, p_admin_password text, p_rpc_secret text DEFAULT ''::text) RETURNS TABLE(juror_id uuid, juror_name text, juror_inst text, project_id uuid, group_no integer, project_title text, poster_date date, criteria_scores jsonb, total integer, comment text, updated_at timestamp with time zone, final_submitted_at timestamp with time zone, status text)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_tpl jsonb;
BEGIN
  IF NOT public._verify_admin_password(p_admin_password, p_rpc_secret) THEN
    RAISE EXCEPTION 'unauthorized' USING ERRCODE = 'P0401'; END IF;
  SELECT criteria_template INTO v_tpl FROM semesters WHERE id = p_semester_id;
  RETURN QUERY
    SELECT j.id, j.juror_name, j.juror_inst, p.id, p.group_no, p.project_title,
      sc.poster_date, sc.criteria_scores, sc.total, sc.comment, sc.updated_at,
      sc.final_submitted_at,
      public._derive_score_status(sc.criteria_scores, v_tpl, a.edit_enabled, sc.final_submitted_at, sc.comment)
    FROM scores sc JOIN jurors j ON j.id = sc.juror_id JOIN projects p ON p.id = sc.project_id
    LEFT JOIN juror_semester_auth a ON a.juror_id = sc.juror_id AND a.semester_id = sc.semester_id
    WHERE sc.semester_id = p_semester_id ORDER BY j.juror_name, p.group_no;
END; $$;


--
-- Name: rpc_admin_get_settings(text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_get_settings(p_admin_password text, p_rpc_secret text DEFAULT ''::text) RETURNS TABLE(key text, value text)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
#variable_conflict use_column
BEGIN
  IF NOT public._verify_admin_password(p_admin_password, p_rpc_secret) THEN
    RAISE EXCEPTION 'unauthorized' USING ERRCODE = 'P0401'; END IF;
  RETURN QUERY SELECT s.key, s.value FROM settings s
    WHERE s.key NOT IN ('pin_secret','rpc_secret','admin_password_hash','delete_password_hash','backup_password_hash')
    ORDER BY s.key;
END; $$;


--
-- Name: rpc_admin_juror_create(text, text, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_juror_create(p_juror_name text, p_juror_inst text, p_semester_id uuid) RETURNS TABLE(juror_id uuid, juror_name text, juror_inst text)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
#variable_conflict use_column
DECLARE v_uid uuid; v_nn text; v_ni text; v_id uuid; v_name text; v_inst text; v_tid uuid; v_pin text; v_hash text;
BEGIN
  v_uid := public._assert_semester_access(p_semester_id);
  SELECT tenant_id INTO v_tid FROM semesters WHERE id = p_semester_id;
  v_nn := lower(regexp_replace(trim(coalesce(p_juror_name,'')), '\\s+', ' ', 'g'));
  v_ni := lower(regexp_replace(trim(coalesce(p_juror_inst,'')), '\\s+', ' ', 'g'));
  SELECT j.id, j.juror_name, j.juror_inst INTO v_id, v_name, v_inst FROM jurors j
  WHERE lower(regexp_replace(trim(coalesce(j.juror_name,'')), '\\s+', ' ', 'g')) = v_nn
    AND lower(regexp_replace(trim(coalesce(j.juror_inst,'')), '\\s+', ' ', 'g')) = v_ni LIMIT 1;
  IF v_id IS NOT NULL THEN RAISE EXCEPTION 'juror_exists'; END IF;
  RETURNING jurors.id, jurors.juror_name, jurors.juror_inst INTO v_id, v_name, v_inst;
  v_pin := lpad((('x' || encode(gen_random_bytes(2), 'hex'))::bit(16)::int % 10000)::text, 4, '0');
  v_hash := crypt(v_pin, gen_salt('bf'));
  ON CONFLICT (juror_id, semester_id) DO NOTHING;
  SELECT p.semester_id, v_tid, p.id, v_id, s.poster_date FROM projects p JOIN semesters s ON s.id = p.semester_id WHERE p.semester_id = p_semester_id
  ON CONFLICT ON CONSTRAINT scores_unique_eval DO NOTHING;
  PERFORM public._audit_log('admin', v_uid, 'juror_create', 'juror', v_id,
    format('Admin created juror %s%s.', COALESCE(v_name,''), CASE WHEN COALESCE(NULLIF(trim(v_inst),''),'') = '' THEN '' ELSE format(' (%s)', v_inst) END),
    jsonb_build_object('semester_id', p_semester_id));
  RETURN QUERY SELECT v_id, v_name, v_inst;
END; $$;


--
-- Name: rpc_admin_juror_delete(uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_juror_delete(p_juror_id uuid, p_delete_password text) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_uid uuid; v_name text;
BEGIN
  IF NOT EXISTS (SELECT 1 FROM juror_semester_auth jsa WHERE jsa.juror_id = p_juror_id) THEN
    v_uid := public._assert_super_admin();
  ELSE
    SELECT public._assert_tenant_admin(jsa.tenant_id) INTO v_uid FROM juror_semester_auth jsa WHERE jsa.juror_id = p_juror_id LIMIT 1;
  END IF;
  PERFORM public._assert_delete_password(p_delete_password);
  SELECT juror_name INTO v_name FROM jurors WHERE id = p_juror_id;
  DELETE FROM jurors WHERE id = p_juror_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'juror_not_found'; END IF;
  PERFORM public._audit_log('admin', v_uid, 'juror_delete', 'juror', p_juror_id,
    format('Admin deleted juror %s.', COALESCE(v_name, p_juror_id::text)), NULL);
  RETURN true;
END; $$;


--
-- Name: rpc_admin_juror_force_close_edit_mode(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_juror_force_close_edit_mode(p_semester_id uuid, p_juror_id uuid) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_uid uuid; v_name text; v_sn text;
BEGIN
  v_uid := public._assert_semester_access(p_semester_id);
  UPDATE juror_semester_auth SET edit_enabled = false WHERE juror_id = p_juror_id AND semester_id = p_semester_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'no_pin'; END IF;
  SELECT juror_name INTO v_name FROM jurors WHERE id = p_juror_id;
  SELECT semester_name INTO v_sn FROM semesters WHERE id = p_semester_id;
  PERFORM public._audit_log('admin', v_uid, 'admin_juror_edit_force_close', 'juror', p_juror_id,
    format('Admin force-closed edit mode for Juror %s (%s).', COALESCE(v_name, p_juror_id::text), COALESCE(v_sn, p_semester_id::text)),
    jsonb_build_object('semester_id', p_semester_id, 'enabled', false));
  RETURN true;
END; $$;


--
-- Name: rpc_admin_juror_list(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_juror_list(p_semester_id uuid) RETURNS TABLE(juror_id uuid, juror_name text, juror_inst text, updated_at timestamp with time zone, locked_until timestamp with time zone, last_seen_at timestamp with time zone, is_locked boolean, is_assigned boolean, scored_semesters text[], edit_enabled boolean, final_submitted_at timestamp with time zone, last_activity_at timestamp with time zone, total_projects integer, completed_projects integer)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
#variable_conflict use_column
DECLARE v_tid uuid;
BEGIN
  PERFORM public._assert_semester_access(p_semester_id);
  SELECT tenant_id INTO v_tid FROM semesters WHERE id = p_semester_id;
  RETURN QUERY
    WITH total AS (SELECT COUNT(*)::int AS total_projects FROM projects p WHERE p.semester_id = p_semester_id),
    completed AS (SELECT sc.juror_id, COUNT(*)::int AS completed_projects FROM scores sc
      WHERE sc.semester_id = p_semester_id AND sc.criteria_scores IS NOT NULL AND sc.criteria_scores <> '{}'::jsonb GROUP BY sc.juror_id)
    SELECT j.id, j.juror_name, j.juror_inst, j.updated_at, a.locked_until, a.last_seen_at,
      (a.locked_until IS NOT NULL AND a.locked_until > now()) AS is_locked,
      (a.juror_id IS NOT NULL OR EXISTS (SELECT 1 FROM scores sc2 WHERE sc2.semester_id = p_semester_id AND sc2.juror_id = j.id)) AS is_assigned,
      COALESCE(ss.scored_semesters, ARRAY[]::text[]), COALESCE(a.edit_enabled, false) AS edit_enabled,
      fs.final_submitted_at, la.last_activity_at,
      COALESCE(t.total_projects, 0) AS total_projects, COALESCE(c.completed_projects, 0) AS completed_projects
    FROM jurors j
    LEFT JOIN juror_semester_auth a ON a.juror_id = j.id AND a.semester_id = p_semester_id
    LEFT JOIN total t ON true
    LEFT JOIN completed c ON c.juror_id = j.id
    LEFT JOIN LATERAL (SELECT MAX(sc.final_submitted_at) AS final_submitted_at FROM scores sc WHERE sc.juror_id = j.id AND sc.semester_id = p_semester_id) AS fs ON true
    LEFT JOIN LATERAL (SELECT GREATEST(MAX(sc.updated_at), MAX(sc.final_submitted_at)) AS last_activity_at FROM scores sc WHERE sc.juror_id = j.id AND sc.semester_id = p_semester_id) AS la ON true
    LEFT JOIN LATERAL (SELECT array_agg(x.semester_name ORDER BY x.poster_date DESC NULLS LAST) AS scored_semesters FROM (
      SELECT DISTINCT s.id, s.semester_name, s.poster_date FROM scores sc JOIN semesters s ON s.id = sc.semester_id
      WHERE sc.juror_id = j.id AND sc.final_submitted_at IS NOT NULL AND s.tenant_id = v_tid) AS x) AS ss ON true
    WHERE EXISTS (SELECT 1 FROM juror_semester_auth jsa2 WHERE jsa2.juror_id = j.id AND jsa2.semester_id = p_semester_id)
    ORDER BY j.juror_name;
END; $$;


--
-- Name: rpc_admin_juror_reset_pin(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_juror_reset_pin(p_semester_id uuid, p_juror_id uuid) RETURNS TABLE(juror_id uuid, pin_plain_once text, failed_attempts integer, locked_until timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
#variable_conflict use_column
DECLARE v_uid uuid; v_tid uuid; v_pin text; v_hash text; v_jn text; v_ji text; v_label text; v_secret text; v_pe text;
BEGIN
  v_uid := public._assert_semester_access(p_semester_id);
  SELECT tenant_id INTO v_tid FROM semesters WHERE id = p_semester_id;
  v_pin := lpad((('x' || encode(gen_random_bytes(2), 'hex'))::bit(16)::int % 10000)::text, 4, '0');
  v_hash := crypt(v_pin, gen_salt('bf'));
  SELECT decrypted_secret INTO v_secret FROM vault.decrypted_secrets WHERE name = 'pin_secret' LIMIT 1;
  IF v_secret IS NULL OR v_secret = '' THEN RAISE EXCEPTION 'pin_secret_missing'; END IF;
  v_pe := 'enc:' || encode(pgp_sym_encrypt(v_pin, v_secret), 'base64');
  SELECT juror_name, juror_inst INTO v_jn, v_ji FROM jurors WHERE id = p_juror_id;
  v_label := COALESCE(NULLIF(trim(v_jn),''), p_juror_id::text);
  IF COALESCE(NULLIF(trim(v_ji),''),'') <> '' THEN v_label := v_label || format(' (%s)', v_ji); END IF;
  VALUES (p_juror_id, p_semester_id, v_tid, v_hash, true, v_pe, 0, null)
  ON CONFLICT (juror_id, semester_id) DO UPDATE SET pin_hash = EXCLUDED.pin_hash, failed_attempts = 0, locked_until = null,
    pin_reveal_pending = true, pin_plain_once = EXCLUDED.pin_plain_once, last_seen_at = null;
  SELECT p_semester_id, v_tid, p.id, p_juror_id, s.poster_date FROM projects p JOIN semesters s ON s.id = p_semester_id WHERE p.semester_id = p_semester_id
  ON CONFLICT ON CONSTRAINT scores_unique_eval DO NOTHING;
  PERFORM public._audit_log('admin', v_uid, 'juror_pin_reset', 'juror', p_juror_id,
    format('Admin reset PIN for juror %s.', v_label), jsonb_build_object('semester_id', p_semester_id));
  RETURN QUERY SELECT p_juror_id, v_pin, 0, null::timestamptz;
END; $$;


--
-- Name: rpc_admin_juror_set_edit_mode(uuid, uuid, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_juror_set_edit_mode(p_semester_id uuid, p_juror_id uuid, p_enabled boolean) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_uid uuid; v_name text; v_sn text; v_hfs boolean := false; v_lk boolean := false;
BEGIN
  v_uid := public._assert_semester_access(p_semester_id);
  SELECT COALESCE(s.is_locked,false) INTO v_lk FROM semesters s WHERE s.id = p_semester_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'semester_not_found'; END IF;
  IF v_lk THEN RAISE EXCEPTION 'semester_locked'; END IF;
  IF COALESCE(p_enabled,false) = false THEN RAISE EXCEPTION 'edit_mode_disable_not_allowed'; END IF;
  SELECT EXISTS (SELECT 1 FROM scores sc WHERE sc.semester_id = p_semester_id AND sc.juror_id = p_juror_id AND sc.final_submitted_at IS NOT NULL) INTO v_hfs;
  IF NOT v_hfs THEN RAISE EXCEPTION 'final_submission_required'; END IF;
  UPDATE juror_semester_auth SET edit_enabled = true WHERE juror_id = p_juror_id AND semester_id = p_semester_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'no_pin'; END IF;
  SELECT juror_name INTO v_name FROM jurors WHERE id = p_juror_id;
  SELECT semester_name INTO v_sn FROM semesters WHERE id = p_semester_id;
  PERFORM public._audit_log('admin', v_uid, 'admin_juror_edit_toggle', 'juror', p_juror_id,
    format('Admin enabled edit mode for Juror %s (%s).', COALESCE(v_name, p_juror_id::text), COALESCE(v_sn, p_semester_id::text)),
    jsonb_build_object('semester_id', p_semester_id, 'enabled', true));
  RETURN true;
END; $$;


--
-- Name: rpc_admin_juror_update(uuid, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_juror_update(p_juror_id uuid, p_juror_name text, p_juror_inst text) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_uid uuid;
BEGIN
  IF NOT EXISTS (SELECT 1 FROM juror_semester_auth jsa WHERE jsa.juror_id = p_juror_id) THEN
    v_uid := public._assert_super_admin();
  ELSE
    SELECT public._assert_tenant_admin(jsa.tenant_id) INTO v_uid FROM juror_semester_auth jsa WHERE jsa.juror_id = p_juror_id LIMIT 1;
  END IF;
  IF trim(coalesce(p_juror_name,'')) = '' OR trim(coalesce(p_juror_inst,'')) = '' THEN RAISE EXCEPTION 'invalid_juror'; END IF;
  UPDATE jurors SET juror_name = trim(p_juror_name), juror_inst = trim(p_juror_inst) WHERE id = p_juror_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'juror_not_found'; END IF;
  PERFORM public._audit_log('admin', v_uid, 'juror_update', 'juror', p_juror_id, format('Admin updated juror %s.', trim(p_juror_name)), NULL);
  RETURN true;
END; $$;


--
-- Name: rpc_admin_list_audit_logs(text, timestamp with time zone, timestamp with time zone, text[], text[], text, integer, integer, integer, integer, timestamp with time zone, uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_list_audit_logs(p_admin_password text, p_start_at timestamp with time zone DEFAULT NULL::timestamp with time zone, p_end_at timestamp with time zone DEFAULT NULL::timestamp with time zone, p_actor_types text[] DEFAULT NULL::text[], p_actions text[] DEFAULT NULL::text[], p_search text DEFAULT NULL::text, p_search_day integer DEFAULT NULL::integer, p_search_month integer DEFAULT NULL::integer, p_search_year integer DEFAULT NULL::integer, p_limit integer DEFAULT 100, p_before_at timestamp with time zone DEFAULT NULL::timestamp with time zone, p_before_id uuid DEFAULT NULL::uuid, p_rpc_secret text DEFAULT ''::text) RETURNS TABLE(id uuid, created_at timestamp with time zone, actor_type text, actor_id uuid, action text, entity_type text, entity_id uuid, message text, metadata jsonb)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_lim integer; v_at text[]; v_ac text[]; v_s text;
BEGIN
  IF NOT public._verify_admin_password(p_admin_password, p_rpc_secret) THEN
    RAISE EXCEPTION 'unauthorized' USING ERRCODE = 'P0401'; END IF;
  v_lim := GREATEST(1, LEAST(COALESCE(p_limit, 100), 500));
  v_at := array_remove(p_actor_types, ''); v_ac := array_remove(p_actions, '');
  IF v_at IS NOT NULL AND array_length(v_at, 1) IS NULL THEN v_at := NULL; END IF;
  IF v_ac IS NOT NULL AND array_length(v_ac, 1) IS NULL THEN v_ac := NULL; END IF;
  v_s := NULLIF(btrim(p_search), '');
  RETURN QUERY SELECT a.id, a.created_at, a.actor_type, a.actor_id, a.action,
    a.entity_type, a.entity_id, a.message, a.metadata
  FROM audit_logs a
  WHERE (p_start_at IS NULL OR a.created_at >= p_start_at)
    AND (p_end_at IS NULL OR a.created_at <= p_end_at)
    AND (v_at IS NULL OR a.actor_type = ANY(v_at))
    AND (v_ac IS NULL OR a.action = ANY(v_ac))
    AND (v_s IS NULL OR a.message ILIKE '%'||v_s||'%' OR a.entity_type ILIKE '%'||v_s||'%'
      OR a.action ILIKE '%'||v_s||'%' OR a.metadata::text ILIKE '%'||v_s||'%'
      OR (p_search_day IS NOT NULL AND p_search_month IS NOT NULL
          AND EXTRACT(DAY FROM a.created_at) = p_search_day AND EXTRACT(MONTH FROM a.created_at) = p_search_month
          AND (p_search_year IS NULL OR EXTRACT(YEAR FROM a.created_at) = p_search_year))
      OR (p_search_day IS NULL AND p_search_month IS NOT NULL
          AND EXTRACT(MONTH FROM a.created_at) = p_search_month
          AND (p_search_year IS NULL OR EXTRACT(YEAR FROM a.created_at) = p_search_year)))
    AND (p_before_at IS NULL OR a.created_at < p_before_at
      OR (a.created_at = p_before_at AND (p_before_id IS NULL OR a.id < p_before_id)))
  ORDER BY a.created_at DESC, a.id DESC LIMIT v_lim;
END; $$;


--
-- Name: rpc_admin_list_jurors(text, uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_list_jurors(p_admin_password text, p_semester_id uuid, p_rpc_secret text DEFAULT ''::text) RETURNS TABLE(juror_id uuid, juror_name text, juror_inst text, updated_at timestamp with time zone, locked_until timestamp with time zone, last_seen_at timestamp with time zone, is_locked boolean, is_assigned boolean, scored_semesters text[], edit_enabled boolean, final_submitted_at timestamp with time zone, last_activity_at timestamp with time zone, total_projects integer, completed_projects integer)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
#variable_conflict use_column
DECLARE v_tid uuid;
BEGIN
  IF NOT public._verify_admin_password(p_admin_password, p_rpc_secret) THEN RAISE EXCEPTION 'unauthorized' USING ERRCODE = 'P0401'; END IF;
  SELECT tenant_id INTO v_tid FROM semesters WHERE id = p_semester_id;
  RETURN QUERY
    WITH total AS (SELECT COUNT(*)::int AS total_projects FROM projects p WHERE p.semester_id = p_semester_id),
    completed AS (SELECT sc.juror_id, COUNT(*)::int AS completed_projects FROM scores sc
      WHERE sc.semester_id = p_semester_id AND sc.criteria_scores IS NOT NULL AND sc.criteria_scores <> '{}'::jsonb GROUP BY sc.juror_id)
    SELECT j.id, j.juror_name, j.juror_inst, j.updated_at, a.locked_until, a.last_seen_at,
      (a.locked_until IS NOT NULL AND a.locked_until > now()) AS is_locked,
      (a.juror_id IS NOT NULL OR EXISTS (SELECT 1 FROM scores sc2 WHERE sc2.semester_id = p_semester_id AND sc2.juror_id = j.id)) AS is_assigned,
      COALESCE(ss.scored_semesters, ARRAY[]::text[]), COALESCE(a.edit_enabled, false) AS edit_enabled,
      fs.final_submitted_at, la.last_activity_at,
      COALESCE(t.total_projects, 0) AS total_projects, COALESCE(c.completed_projects, 0) AS completed_projects
    FROM jurors j
    LEFT JOIN juror_semester_auth a ON a.juror_id = j.id AND a.semester_id = p_semester_id
    LEFT JOIN total t ON true
    LEFT JOIN completed c ON c.juror_id = j.id
    LEFT JOIN LATERAL (SELECT MAX(sc.final_submitted_at) AS final_submitted_at FROM scores sc WHERE sc.juror_id = j.id AND sc.semester_id = p_semester_id) AS fs ON true
    LEFT JOIN LATERAL (SELECT GREATEST(MAX(sc.updated_at), MAX(sc.final_submitted_at)) AS last_activity_at FROM scores sc WHERE sc.juror_id = j.id AND sc.semester_id = p_semester_id) AS la ON true
    LEFT JOIN LATERAL (SELECT array_agg(x.semester_name ORDER BY x.poster_date DESC NULLS LAST) AS scored_semesters FROM (
      SELECT DISTINCT s.id, s.semester_name, s.poster_date FROM scores sc JOIN semesters s ON s.id = sc.semester_id
      WHERE sc.juror_id = j.id AND sc.final_submitted_at IS NOT NULL AND s.tenant_id = v_tid) AS x) AS ss ON true
    WHERE EXISTS (SELECT 1 FROM juror_semester_auth jsa2 WHERE jsa2.juror_id = j.id AND jsa2.semester_id = p_semester_id)
    ORDER BY j.juror_name;
END; $$;


