CREATE FUNCTION public.rpc_admin_list_projects(p_semester_id uuid, p_admin_password text, p_rpc_secret text DEFAULT ''::text) RETURNS TABLE(id uuid, semester_id uuid, group_no integer, project_title text, group_students text, updated_at timestamp with time zone)
