--
-- Name: rpc_admin_login(text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_login(p_password text, p_rpc_secret text DEFAULT ''::text) RETURNS TABLE(ok boolean, locked_until timestamp with time zone, failed_attempts integer)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE
  v_attempts_str text; v_locked_str text; v_attempts integer;
  v_locked timestamptz; v_new_locked timestamptz; v_now timestamptz := now(); v_ok boolean;
BEGIN
  SELECT value INTO v_attempts_str FROM settings WHERE key = 'admin_failed_attempts' AND tenant_id IS NULL;
  SELECT value INTO v_locked_str FROM settings WHERE key = 'admin_locked_until' AND tenant_id IS NULL;
  v_attempts := COALESCE(v_attempts_str::integer, 0);
  v_locked := CASE WHEN v_locked_str IS NOT NULL AND v_locked_str <> '' THEN v_locked_str::timestamptz ELSE NULL END;
  -- Reject if still locked
  IF v_locked IS NOT NULL AND v_locked > v_now THEN
    RETURN QUERY SELECT false, v_locked, v_attempts; RETURN; END IF;
  -- Lock expired: reset
  IF v_locked IS NOT NULL AND v_locked <= v_now THEN
      ON CONFLICT (key) WHERE tenant_id IS NULL DO UPDATE SET value = '0', updated_at = now();
      ON CONFLICT (key) WHERE tenant_id IS NULL DO UPDATE SET value = '', updated_at = now();
    v_attempts := 0; v_locked := NULL;
  END IF;
  v_ok := public._verify_admin_password(p_password, p_rpc_secret);
  IF v_ok THEN
      ON CONFLICT (key) WHERE tenant_id IS NULL DO UPDATE SET value = '0', updated_at = now();
      ON CONFLICT (key) WHERE tenant_id IS NULL DO UPDATE SET value = '', updated_at = now();
    RETURN QUERY SELECT true, null::timestamptz, 0; RETURN;
  END IF;
  v_attempts := v_attempts + 1; v_new_locked := NULL;
  IF v_attempts >= 5 THEN v_new_locked := v_now + interval '15 minutes'; END IF;
    ON CONFLICT (key) WHERE tenant_id IS NULL DO UPDATE SET value = v_attempts::text, updated_at = now();
  IF v_new_locked IS NOT NULL THEN
      ON CONFLICT (key) WHERE tenant_id IS NULL DO UPDATE SET value = v_new_locked::text, updated_at = now();
  END IF;
  PERFORM public._audit_log('system', null::uuid, 'admin_login_failed', 'settings', null::uuid,
    'Admin login failed. Attempt ' || v_attempts || '.' ||
    CASE WHEN v_new_locked IS NOT NULL THEN ' Account locked until ' || v_new_locked::text || '.' ELSE '' END, null);
  RETURN QUERY SELECT false, v_new_locked, v_attempts;
END; $$;


--
-- Name: rpc_admin_outcome_trends(uuid[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_outcome_trends(p_semester_ids uuid[]) RETURNS TABLE(semester_id uuid, semester_name text, poster_date date, criteria_avgs jsonb, n_evals bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
BEGIN
  IF auth.uid() IS NULL THEN RAISE EXCEPTION 'unauthorized' USING ERRCODE = 'P0401'; END IF;
  IF NOT EXISTS (SELECT 1 FROM tenant_admin_memberships WHERE user_id = auth.uid()) THEN
    RAISE EXCEPTION 'unauthorized' USING ERRCODE = 'P0401'; END IF;
  RETURN QUERY
    SELECT s.id, s.semester_name, s.poster_date,
      (SELECT COALESCE(jsonb_object_agg(key, avg_val), '{}'::jsonb) FROM (
        SELECT c->>'key' AS key,
          ROUND(AVG((sc2.criteria_scores->>(c->>'key'))::numeric), 2) AS avg_val
        FROM jsonb_array_elements(COALESCE(s.criteria_template, '[]'::jsonb)) c
        LEFT JOIN scores sc2 ON sc2.semester_id = s.id
          AND sc2.criteria_scores IS NOT NULL AND sc2.final_submitted_at IS NOT NULL
          AND EXISTS (SELECT 1 FROM juror_semester_auth a2
            WHERE a2.juror_id = sc2.juror_id AND a2.semester_id = sc2.semester_id
              AND COALESCE(a2.edit_enabled, false) = false)
        GROUP BY c->>'key') sub),
      COUNT(sc.juror_id)
    FROM semesters s
    LEFT JOIN scores sc ON sc.semester_id = s.id
      AND sc.criteria_scores IS NOT NULL AND sc.final_submitted_at IS NOT NULL
      AND EXISTS (SELECT 1 FROM juror_semester_auth a
        WHERE a.juror_id = sc.juror_id AND a.semester_id = sc.semester_id
          AND COALESCE(a.edit_enabled, false) = false)
    WHERE (p_semester_ids IS NULL OR s.id = ANY(p_semester_ids))
    GROUP BY s.id, s.semester_name, s.poster_date, s.criteria_template
    ORDER BY s.semester_name;
END; $$;


--
-- Name: rpc_admin_outcome_trends(uuid[], text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_outcome_trends(p_semester_ids uuid[], p_admin_password text, p_rpc_secret text DEFAULT ''::text) RETURNS TABLE(semester_id uuid, semester_name text, poster_date date, criteria_avgs jsonb, n_evals bigint)
    LANGUAGE plpgsql SECURITY DEFINER
