CREATE FUNCTION public.rpc_admin_profile_get() RETURNS TABLE(user_id uuid, display_name text)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_uid uuid;
BEGIN
  v_uid := public._get_auth_user_id();
  RETURN QUERY SELECT ap.user_id, ap.display_name FROM admin_profiles ap WHERE ap.user_id = v_uid;
END; $$;


--
-- Name: rpc_admin_profile_upsert(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_profile_upsert(p_display_name text DEFAULT NULL::text) RETURNS TABLE(out_user_id uuid, out_display_name text)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_uid uuid;
BEGIN
  v_uid := public._get_auth_user_id();
  ON CONFLICT (user_id) DO UPDATE SET display_name = COALESCE(NULLIF(trim(EXCLUDED.display_name),''), admin_profiles.display_name), updated_at = now();
  RETURN QUERY SELECT ap.user_id, ap.display_name FROM admin_profiles ap WHERE ap.user_id = v_uid;
END; $$;


--
-- Name: rpc_admin_project_create(uuid, integer, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_project_create(p_semester_id uuid, p_group_no integer, p_project_title text, p_group_students text) RETURNS TABLE(project_id uuid)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_uid uuid; v_id uuid; v_tid uuid; v_sn text; v_lk boolean := false;
BEGIN
  v_uid := public._assert_semester_access(p_semester_id);
  SELECT tenant_id, semester_name, COALESCE(is_locked,false) INTO v_tid, v_sn, v_lk FROM semesters WHERE id = p_semester_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'semester_not_found'; END IF;
  IF v_lk THEN RAISE EXCEPTION 'semester_locked'; END IF;
  IF EXISTS (SELECT 1 FROM projects WHERE semester_id = p_semester_id AND group_no = p_group_no) THEN RAISE EXCEPTION 'project_group_exists'; END IF;
  VALUES (p_semester_id, v_tid, p_group_no, p_project_title, p_group_students) RETURNING id INTO v_id;
  SELECT jsa.semester_id, v_tid, v_id, jsa.juror_id, sem.poster_date
  FROM juror_semester_auth jsa JOIN semesters sem ON sem.id = jsa.semester_id WHERE jsa.semester_id = p_semester_id
  ON CONFLICT ON CONSTRAINT scores_unique_eval DO NOTHING;
  PERFORM public._audit_log('admin', v_uid, 'project_create', 'project', v_id,
    format('Admin created project Group %s — %s (%s).', p_group_no, p_project_title, COALESCE(v_sn, p_semester_id::text)),
    jsonb_build_object('semester_id', p_semester_id, 'group_no', p_group_no, 'semester_name', v_sn));
  RETURN QUERY SELECT v_id;
END; $$;


--
-- Name: rpc_admin_project_delete(uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_project_delete(p_project_id uuid, p_delete_password text) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_uid uuid; v_title text; v_grp integer; v_sid uuid; v_lk boolean := false; v_hs boolean := false;
BEGIN
  SELECT project_title, group_no, semester_id INTO v_title, v_grp, v_sid FROM projects WHERE id = p_project_id;
  IF v_sid IS NULL THEN RAISE EXCEPTION 'project_not_found'; END IF;
  v_uid := public._assert_semester_access(v_sid);
  PERFORM public._assert_delete_password(p_delete_password);
  SELECT COALESCE(is_locked,false) INTO v_lk FROM semesters WHERE id = v_sid;
  IF v_lk THEN RAISE EXCEPTION 'semester_locked'; END IF;
  SELECT EXISTS (SELECT 1 FROM scores s WHERE s.project_id = p_project_id
    AND (s.final_submitted_at IS NOT NULL OR (s.criteria_scores IS NOT NULL AND s.criteria_scores <> '{}'::jsonb))) INTO v_hs;
  IF v_hs THEN RAISE EXCEPTION 'project_has_scored_data'; END IF;
  DELETE FROM projects WHERE id = p_project_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'project_not_found'; END IF;
  PERFORM public._audit_log('admin', v_uid, 'project_delete', 'project', p_project_id,
    format('Admin deleted project Group %s — %s.', COALESCE(v_grp::text,'?'), COALESCE(v_title, p_project_id::text)),
    jsonb_build_object('group_no', v_grp, 'semester_id', v_sid));
  RETURN true;
END; $$;


--
-- Name: rpc_admin_project_list(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_project_list(p_semester_id uuid) RETURNS TABLE(id uuid, semester_id uuid, group_no integer, project_title text, group_students text, updated_at timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
#variable_conflict use_column
BEGIN
  PERFORM public._assert_semester_access(p_semester_id);
  RETURN QUERY SELECT p.id, p.semester_id, p.group_no, p.project_title, p.group_students, p.updated_at
    FROM projects p WHERE p.semester_id = p_semester_id ORDER BY p.group_no ASC;
END; $$;


--
-- Name: rpc_admin_project_summary(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_project_summary(p_semester_id uuid) RETURNS TABLE(project_id uuid, group_no integer, project_title text, group_students text, juror_count bigint, criteria_avgs jsonb, avg_total numeric, min_total integer, max_total integer, note text)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_tpl jsonb;
BEGIN
  PERFORM public._assert_semester_access(p_semester_id);
  SELECT criteria_template INTO v_tpl FROM semesters WHERE id = p_semester_id;
  RETURN QUERY
    SELECT p.id, p.group_no, p.project_title, p.group_students,
      COUNT(sc.juror_id),
      public._criteria_avgs_for_project(p.id, p_semester_id, v_tpl),
      ROUND(AVG(sc.total), 2), MIN(sc.total), MAX(sc.total), ''::text
    FROM projects p
    LEFT JOIN scores sc ON sc.project_id = p.id AND sc.semester_id = p_semester_id
      AND sc.criteria_scores IS NOT NULL AND sc.final_submitted_at IS NOT NULL
      AND EXISTS (SELECT 1 FROM juror_semester_auth a
        WHERE a.juror_id = sc.juror_id AND a.semester_id = sc.semester_id
          AND COALESCE(a.edit_enabled, false) = false)
    WHERE p.semester_id = p_semester_id
    GROUP BY p.id, p.group_no, p.project_title, p.group_students
    ORDER BY p.group_no;
END; $$;


--
-- Name: rpc_admin_project_summary(uuid, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_project_summary(p_semester_id uuid, p_admin_password text, p_rpc_secret text DEFAULT ''::text) RETURNS TABLE(project_id uuid, group_no integer, project_title text, group_students text, juror_count bigint, criteria_avgs jsonb, avg_total numeric, min_total integer, max_total integer, note text)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_tpl jsonb;
BEGIN
  IF NOT public._verify_admin_password(p_admin_password, p_rpc_secret) THEN
    RAISE EXCEPTION 'unauthorized' USING ERRCODE = 'P0401'; END IF;
  SELECT criteria_template INTO v_tpl FROM semesters WHERE id = p_semester_id;
  RETURN QUERY
    SELECT p.id, p.group_no, p.project_title, p.group_students, COUNT(sc.juror_id),
      public._criteria_avgs_for_project(p.id, p_semester_id, v_tpl),
      ROUND(AVG(sc.total), 2), MIN(sc.total), MAX(sc.total), ''::text
    FROM projects p
    LEFT JOIN scores sc ON sc.project_id = p.id AND sc.semester_id = p_semester_id
      AND sc.criteria_scores IS NOT NULL AND sc.final_submitted_at IS NOT NULL
      AND EXISTS (SELECT 1 FROM juror_semester_auth a
        WHERE a.juror_id = sc.juror_id AND a.semester_id = sc.semester_id
          AND COALESCE(a.edit_enabled, false) = false)
    WHERE p.semester_id = p_semester_id
    GROUP BY p.id, p.group_no, p.project_title, p.group_students ORDER BY p.group_no;
END; $$;


--
-- Name: rpc_admin_project_upsert(uuid, integer, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_project_upsert(p_semester_id uuid, p_group_no integer, p_project_title text, p_group_students text) RETURNS TABLE(project_id uuid)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_uid uuid; v_id uuid; v_tid uuid; v_cr boolean := false; v_act text; v_msg text; v_sn text; v_lk boolean := false;
BEGIN
  v_uid := public._assert_semester_access(p_semester_id);
  SELECT tenant_id, semester_name, COALESCE(is_locked,false) INTO v_tid, v_sn, v_lk FROM semesters WHERE id = p_semester_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'semester_not_found'; END IF;
  IF v_lk THEN RAISE EXCEPTION 'semester_locked'; END IF;
  SELECT id INTO v_id FROM projects WHERE semester_id = p_semester_id AND group_no = p_group_no LIMIT 1;
  IF v_id IS NULL THEN
    VALUES (p_semester_id, v_tid, p_group_no, p_project_title, p_group_students) RETURNING id INTO v_id;
    v_cr := true;
  ELSE
    UPDATE projects SET project_title = p_project_title, group_students = p_group_students WHERE id = v_id;
  END IF;
  v_act := CASE WHEN v_cr THEN 'project_create' ELSE 'project_update' END;
  v_msg := format('Admin %s project Group %s — %s (%s).', CASE WHEN v_cr THEN 'created' ELSE 'updated' END, p_group_no, p_project_title, COALESCE(v_sn, p_semester_id::text));
  PERFORM public._audit_log('admin', v_uid, v_act, 'project', v_id, v_msg,
    jsonb_build_object('semester_id', p_semester_id, 'group_no', p_group_no, 'semester_name', v_sn));
  RETURN QUERY SELECT v_id;
END; $$;


--
-- Name: rpc_admin_reset_juror_pin(uuid, uuid, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_reset_juror_pin(p_semester_id uuid, p_juror_id uuid, p_admin_password text, p_rpc_secret text DEFAULT ''::text) RETURNS TABLE(juror_id uuid, pin_plain_once text, failed_attempts integer, locked_until timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
#variable_conflict use_column
DECLARE v_tid uuid; v_pin text; v_hash text; v_jn text; v_ji text; v_label text; v_secret text; v_pe text;
BEGIN
  IF NOT public._verify_admin_password(p_admin_password, p_rpc_secret) THEN RAISE EXCEPTION 'unauthorized' USING ERRCODE = 'P0401'; END IF;
  SELECT tenant_id INTO v_tid FROM semesters WHERE id = p_semester_id;
  v_pin := lpad((('x' || encode(gen_random_bytes(2), 'hex'))::bit(16)::int % 10000)::text, 4, '0');
  v_hash := crypt(v_pin, gen_salt('bf'));
  SELECT decrypted_secret INTO v_secret FROM vault.decrypted_secrets WHERE name = 'pin_secret' LIMIT 1;
  IF v_secret IS NULL OR v_secret = '' THEN RAISE EXCEPTION 'pin_secret_missing'; END IF;
  v_pe := 'enc:' || encode(pgp_sym_encrypt(v_pin, v_secret), 'base64');
  SELECT juror_name, juror_inst INTO v_jn, v_ji FROM jurors WHERE id = p_juror_id;
  v_label := COALESCE(NULLIF(trim(v_jn),''), p_juror_id::text);
  IF COALESCE(NULLIF(trim(v_ji),''),'') <> '' THEN v_label := v_label || format(' (%s)', v_ji); END IF;
  VALUES (p_juror_id, p_semester_id, COALESCE(v_tid, gen_random_uuid()), v_hash, true, v_pe, 0, null)
  ON CONFLICT (juror_id, semester_id) DO UPDATE SET pin_hash = EXCLUDED.pin_hash, failed_attempts = 0, locked_until = null,
    pin_reveal_pending = true, pin_plain_once = EXCLUDED.pin_plain_once, last_seen_at = null;
  SELECT p_semester_id, COALESCE(v_tid, gen_random_uuid()), p.id, p_juror_id, s.poster_date
  FROM projects p JOIN semesters s ON s.id = p_semester_id WHERE p.semester_id = p_semester_id
  ON CONFLICT ON CONSTRAINT scores_unique_eval DO NOTHING;
  PERFORM public._audit_log('admin', null::uuid, 'juror_pin_reset', 'juror', p_juror_id,
    format('Admin reset PIN for juror %s.', v_label), jsonb_build_object('semester_id', p_semester_id));
  RETURN QUERY SELECT p_juror_id, v_pin, 0, null::timestamptz;
END; $$;


--
-- Name: rpc_admin_revoke_entry_token(uuid, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_revoke_entry_token(p_semester_id uuid, p_admin_password text, p_rpc_secret text DEFAULT ''::text) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_sn text;
BEGIN
  IF NOT public._verify_admin_password(p_admin_password, p_rpc_secret) THEN
    RAISE EXCEPTION 'unauthorized' USING ERRCODE = 'P0401'; END IF;
  UPDATE semesters SET entry_token_enabled = false, updated_at = now()
  WHERE id = p_semester_id RETURNING semester_name INTO v_sn;
  IF NOT FOUND THEN RAISE EXCEPTION 'semester_not_found'; END IF;
  PERFORM public._audit_log('admin', null::uuid, 'entry_token_revoke', 'semester', p_semester_id,
    format('Jury entry token revoked (%s)', coalesce(v_sn, p_semester_id::text)),
    jsonb_build_object('semester_id', p_semester_id));
  RETURN true;
END; $$;


--
-- Name: rpc_admin_scores_get(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_scores_get(p_semester_id uuid) RETURNS TABLE(juror_id uuid, juror_name text, juror_inst text, project_id uuid, group_no integer, project_title text, poster_date date, criteria_scores jsonb, total integer, comment text, updated_at timestamp with time zone, final_submitted_at timestamp with time zone, status text)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_tpl jsonb;
BEGIN
  PERFORM public._assert_semester_access(p_semester_id);
  SELECT criteria_template INTO v_tpl FROM semesters WHERE id = p_semester_id;
  RETURN QUERY
    SELECT j.id, j.juror_name, j.juror_inst, p.id, p.group_no, p.project_title,
      sc.poster_date, sc.criteria_scores, sc.total, sc.comment, sc.updated_at,
      sc.final_submitted_at,
      public._derive_score_status(sc.criteria_scores, v_tpl, a.edit_enabled, sc.final_submitted_at, sc.comment)
    FROM scores sc
    JOIN jurors j ON j.id = sc.juror_id
    JOIN projects p ON p.id = sc.project_id
    LEFT JOIN juror_semester_auth a ON a.juror_id = sc.juror_id AND a.semester_id = sc.semester_id
    WHERE sc.semester_id = p_semester_id
    ORDER BY j.juror_name, p.group_no;
END; $$;


--
-- Name: rpc_admin_security_state(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_security_state() RETURNS TABLE(admin_password_set boolean, delete_password_set boolean, backup_password_set boolean)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
BEGIN
  RETURN QUERY SELECT
    EXISTS (SELECT 1 FROM settings WHERE key = 'admin_password_hash' AND tenant_id IS NULL AND value IS NOT NULL AND value <> ''),
    EXISTS (SELECT 1 FROM settings WHERE key = 'delete_password_hash' AND tenant_id IS NULL AND value IS NOT NULL AND value <> ''),
    EXISTS (SELECT 1 FROM settings WHERE key = 'backup_password_hash' AND tenant_id IS NULL AND value IS NOT NULL AND value <> '');
END; $$;


--
-- Name: rpc_admin_semester_create(uuid, text, date, jsonb, jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_semester_create(p_tenant_id uuid, p_semester_name text, p_poster_date date DEFAULT NULL::date, p_criteria_template jsonb DEFAULT NULL::jsonb, p_mudek_template jsonb DEFAULT NULL::jsonb) RETURNS TABLE(id uuid, semester_name text, is_current boolean, poster_date date, criteria_template jsonb, mudek_template jsonb)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
#variable_conflict use_column
DECLARE v_uid uuid; v_id uuid; v_sn text; v_cur boolean; v_pd date; v_ct jsonb; v_mt jsonb;
BEGIN
  v_uid := public._assert_tenant_admin(p_tenant_id);
  v_sn := trim(p_semester_name);
  IF v_sn IS NULL OR v_sn = '' THEN RAISE EXCEPTION 'semester_name_required'; END IF;
  IF EXISTS (SELECT 1 FROM semesters s WHERE s.tenant_id = p_tenant_id AND lower(trim(s.semester_name)) = lower(v_sn)) THEN
    RAISE EXCEPTION 'semester_name_exists'; END IF;
  VALUES (p_tenant_id, v_sn, false, p_poster_date, COALESCE(p_criteria_template,'[]'::jsonb), COALESCE(p_mudek_template,'[]'::jsonb))
  RETURNING semesters.id, semesters.semester_name, semesters.is_current, semesters.poster_date, semesters.criteria_template, semesters.mudek_template
    INTO v_id, v_sn, v_cur, v_pd, v_ct, v_mt;
  PERFORM public._audit_log('admin', v_uid, 'semester_create', 'semester', v_id,
    format('Admin created semester %s.', v_sn), jsonb_build_object('poster_date', v_pd, 'tenant_id', p_tenant_id));
  RETURN QUERY SELECT v_id, v_sn, v_cur, v_pd, v_ct, v_mt;
END; $$;


--
-- Name: rpc_admin_semester_delete(uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_semester_delete(p_semester_id uuid, p_delete_password text) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_uid uuid; v_name text;
BEGIN
  v_uid := public._assert_semester_access(p_semester_id);
  PERFORM public._assert_delete_password(p_delete_password);
  SELECT semester_name INTO v_name FROM semesters WHERE id = p_semester_id;
  DELETE FROM semesters WHERE id = p_semester_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'semester_not_found'; END IF;
  PERFORM public._audit_log('admin', v_uid, 'semester_delete', 'semester', p_semester_id,
    format('Admin deleted semester %s.', COALESCE(v_name, p_semester_id::text)), NULL);
  RETURN true;
END; $$;


--
-- Name: rpc_admin_semester_list(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_semester_list(p_tenant_id uuid) RETURNS TABLE(id uuid, semester_name text, is_current boolean, is_locked boolean, poster_date date, updated_at timestamp with time zone, criteria_template jsonb, mudek_template jsonb)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
BEGIN
  PERFORM public._assert_tenant_admin(p_tenant_id);
  RETURN QUERY SELECT s.id, s.semester_name, s.is_current, s.is_locked, s.poster_date, s.updated_at, s.criteria_template, s.mudek_template
    FROM semesters s WHERE s.tenant_id = p_tenant_id ORDER BY s.poster_date DESC NULLS LAST;
END; $$;


--
-- Name: rpc_admin_semester_set_current(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_semester_set_current(p_semester_id uuid) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_uid uuid; v_name text; v_tid uuid;
BEGIN
  v_uid := public._assert_semester_access(p_semester_id);
  SELECT semester_name, tenant_id INTO v_name, v_tid FROM semesters WHERE id = p_semester_id;
  IF v_name IS NULL THEN RAISE EXCEPTION 'semester_not_found'; END IF;
  UPDATE semesters SET is_current = false WHERE tenant_id = v_tid AND id <> p_semester_id;
  UPDATE semesters SET is_current = true WHERE id = p_semester_id;
  PERFORM public._audit_log('admin', v_uid, 'set_current_semester', 'semester', p_semester_id,
    format('Admin set current semester to %s.', COALESCE(v_name, p_semester_id::text)), NULL);
  RETURN true;
END; $$;


--
-- Name: rpc_admin_semester_set_eval_lock(uuid, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_semester_set_eval_lock(p_semester_id uuid, p_enabled boolean) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_uid uuid; v_sn text; v_en boolean := COALESCE(p_enabled, false);
BEGIN
  v_uid := public._assert_semester_access(p_semester_id);
  UPDATE semesters s SET is_locked = v_en, updated_at = now() WHERE s.id = p_semester_id RETURNING s.semester_name INTO v_sn;
  IF NOT FOUND THEN RAISE EXCEPTION 'semester_not_found'; END IF;
  PERFORM public._audit_log('admin', v_uid, 'eval_lock_toggle', 'semester', p_semester_id,
    format('Admin turned evaluation lock %s (%s).', CASE WHEN v_en THEN 'ON' ELSE 'OFF' END, COALESCE(v_sn, p_semester_id::text)),
    jsonb_build_object('semester_id', p_semester_id, 'semester_name', v_sn, 'enabled', v_en));
  RETURN true;
END; $$;


--
-- Name: rpc_admin_semester_update(uuid, text, date, jsonb, jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_semester_update(p_semester_id uuid, p_semester_name text, p_poster_date date DEFAULT NULL::date, p_criteria_template jsonb DEFAULT NULL::jsonb, p_mudek_template jsonb DEFAULT NULL::jsonb) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_uid uuid; v_name text; v_tid uuid; v_hs boolean := false;
BEGIN
  v_uid := public._assert_semester_access(p_semester_id);
  SELECT tenant_id INTO v_tid FROM semesters WHERE id = p_semester_id;
  v_name := trim(p_semester_name);
  IF v_name IS NULL OR v_name = '' THEN RAISE EXCEPTION 'semester_name_required'; END IF;
  IF EXISTS (SELECT 1 FROM semesters s WHERE s.tenant_id = v_tid AND lower(trim(s.semester_name)) = lower(v_name) AND s.id <> p_semester_id) THEN
    RAISE EXCEPTION 'semester_name_exists'; END IF;
  IF p_criteria_template IS NOT NULL OR p_mudek_template IS NOT NULL THEN
    IF EXISTS (SELECT 1 FROM semesters WHERE id = p_semester_id AND is_locked = TRUE) THEN RAISE EXCEPTION 'semester_template_locked_by_scores'; END IF;
    SELECT EXISTS (SELECT 1 FROM scores sc WHERE sc.semester_id = p_semester_id
      AND (sc.final_submitted_at IS NOT NULL OR (sc.criteria_scores IS NOT NULL AND sc.criteria_scores <> '{}'::jsonb))) INTO v_hs;
    IF v_hs THEN RAISE EXCEPTION 'semester_template_locked_by_scores'; END IF;
  END IF;
  UPDATE semesters SET semester_name = v_name, poster_date = p_poster_date,
    criteria_template = COALESCE(p_criteria_template, criteria_template), mudek_template = COALESCE(p_mudek_template, mudek_template)
  WHERE id = p_semester_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'semester_not_found'; END IF;
  PERFORM public._audit_log('admin', v_uid, 'semester_update', 'semester', p_semester_id, format('Admin updated semester %s.', v_name), NULL);
  RETURN true;
END; $$;


--
-- Name: rpc_admin_set_current_semester(uuid, text, text); Type: FUNCTION; Schema: public; Owner: -
