  IF NOT public._verify_admin_password(p_admin_password, p_rpc_secret) THEN RAISE EXCEPTION 'unauthorized' USING ERRCODE = 'P0401'; END IF;
  UPDATE semesters s SET is_locked = v_en, updated_at = now() WHERE s.id = p_semester_id RETURNING s.semester_name INTO v_sn;
  IF NOT FOUND THEN RAISE EXCEPTION 'semester_not_found'; END IF;
  PERFORM public._audit_log('admin', null::uuid, 'eval_lock_toggle', 'semester', p_semester_id,
    format('Admin turned evaluation lock %s (%s).', CASE WHEN v_en THEN 'ON' ELSE 'OFF' END, COALESCE(v_sn, p_semester_id::text)),
    jsonb_build_object('semester_id', p_semester_id, 'semester_name', v_sn, 'enabled', v_en));
  RETURN true;
END; $$;


--
-- Name: rpc_admin_set_setting(text, text, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_set_setting(p_key text, p_value text, p_admin_password text, p_rpc_secret text DEFAULT ''::text) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
#variable_conflict use_column
BEGIN
  IF NOT public._verify_admin_password(p_admin_password, p_rpc_secret) THEN
    RAISE EXCEPTION 'unauthorized' USING ERRCODE = 'P0401'; END IF;
  ON CONFLICT (key) WHERE tenant_id IS NULL DO UPDATE SET value = EXCLUDED.value, updated_at = now();
  PERFORM public._audit_log('admin', null::uuid, 'setting_change', 'settings', null::uuid,
    format('Admin changed setting %s.', COALESCE(NULLIF(trim(p_key), ''), '?')),
    jsonb_build_object('key', p_key));
  RETURN true;
END; $$;


--
-- Name: rpc_admin_setting_set(uuid, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_setting_set(p_tenant_id uuid, p_key text, p_value text) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
BEGIN
  PERFORM public._assert_tenant_admin(p_tenant_id);
  ON CONFLICT (key, COALESCE(tenant_id, '00000000-0000-0000-0000-000000000000'::uuid))
    DO UPDATE SET value = EXCLUDED.value, updated_at = now();
  PERFORM public._audit_log('admin', auth.uid(), 'setting_change', 'settings', null::uuid,
    format('Admin changed setting %s.', COALESCE(NULLIF(trim(p_key), ''), '?')),
    jsonb_build_object('key', p_key, 'tenant_id', p_tenant_id));
  RETURN true;
END; $$;


--
-- Name: rpc_admin_settings_get(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_settings_get(p_tenant_id uuid) RETURNS TABLE(key text, value text)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
#variable_conflict use_column
BEGIN
  PERFORM public._assert_tenant_admin(p_tenant_id);
  RETURN QUERY SELECT s.key, s.value FROM settings s
    WHERE (s.tenant_id = p_tenant_id OR s.tenant_id IS NULL)
      AND s.key NOT IN ('pin_secret','rpc_secret','admin_password_hash','delete_password_hash','backup_password_hash')
    ORDER BY s.key;
END; $$;


--
-- Name: rpc_admin_tenant_admin_delete_hard(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_tenant_admin_delete_hard(p_tenant_id uuid, p_user_id uuid) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE
  v_uid uuid;
  v_target_email text;
BEGIN
  v_uid := public._assert_super_admin();

  IF p_tenant_id IS NULL THEN RAISE EXCEPTION 'tenant_id_required'; END IF;
  IF p_user_id IS NULL THEN RAISE EXCEPTION 'user_id_required'; END IF;
  IF p_user_id = v_uid THEN RAISE EXCEPTION 'cannot_delete_self'; END IF;

  IF EXISTS (
    SELECT 1
    FROM tenant_admin_memberships tam
    WHERE tam.user_id = p_user_id
      AND tam.role = 'super_admin'
  ) THEN
    RAISE EXCEPTION 'cannot_delete_super_admin';
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM tenant_admin_memberships tam
    WHERE tam.user_id = p_user_id
      AND tam.tenant_id = p_tenant_id
      AND tam.role = 'tenant_admin'
  ) THEN
    RAISE EXCEPTION 'tenant_admin_not_found';
  END IF;

  SELECT lower(trim(u.email))
  INTO v_target_email
  FROM auth.users u
  WHERE u.id = p_user_id;

  DELETE FROM auth.identities WHERE user_id = p_user_id;
  DELETE FROM auth.users WHERE id = p_user_id;
  DELETE FROM tenant_admin_memberships WHERE user_id = p_user_id;
  DELETE FROM admin_profiles WHERE user_id = p_user_id;

  PERFORM public._audit_log(
    'admin',
    v_uid,
    'tenant_admin_delete_hard',
    'tenant',
    p_tenant_id,
    format('Hard-deleted tenant admin %s.', COALESCE(v_target_email, p_user_id::text)),
    jsonb_build_object('target_user_id', p_user_id)
  );

  RETURN true;
END; $$;


--
-- Name: rpc_admin_tenant_admin_update(uuid, uuid, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_tenant_admin_update(p_tenant_id uuid, p_user_id uuid, p_name text DEFAULT NULL::text, p_email text DEFAULT NULL::text) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE
  v_uid uuid;
  v_new_name text;
  v_new_email text;
BEGIN
  v_uid := public._assert_super_admin();

  IF p_tenant_id IS NULL THEN RAISE EXCEPTION 'tenant_id_required'; END IF;
  IF p_user_id IS NULL THEN RAISE EXCEPTION 'user_id_required'; END IF;
  IF p_user_id = v_uid THEN RAISE EXCEPTION 'cannot_edit_self'; END IF;

  IF EXISTS (
    SELECT 1
    FROM tenant_admin_memberships tam
    WHERE tam.user_id = p_user_id
      AND tam.role = 'super_admin'
  ) THEN
    RAISE EXCEPTION 'cannot_modify_super_admin';
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM tenant_admin_memberships tam
    WHERE tam.user_id = p_user_id
      AND tam.tenant_id = p_tenant_id
      AND tam.role = 'tenant_admin'
  ) THEN
    RAISE EXCEPTION 'tenant_admin_not_found';
  END IF;

  v_new_name := NULLIF(trim(COALESCE(p_name, '')), '');
  v_new_email := NULLIF(lower(trim(COALESCE(p_email, ''))), '');

  IF v_new_name IS NULL AND v_new_email IS NULL THEN
    RAISE EXCEPTION 'nothing_to_update';
  END IF;

  IF v_new_email IS NOT NULL THEN
    IF position('@' in v_new_email) < 2 THEN
      RAISE EXCEPTION 'invalid_email';
    END IF;

    IF EXISTS (
      SELECT 1
      FROM auth.users u
      WHERE lower(trim(u.email)) = v_new_email
        AND u.id <> p_user_id
    ) THEN
      RAISE EXCEPTION 'email_already_in_use';
    END IF;

    UPDATE auth.users
    SET email = v_new_email, updated_at = now()
    WHERE id = p_user_id;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'user_not_found';
    END IF;

    UPDATE auth.identities
    SET
      provider_id = v_new_email,
      identity_data = jsonb_set(
        COALESCE(identity_data, '{}'::jsonb),
        '{email}',
        to_jsonb(v_new_email),
        true
      ),
      updated_at = now()
    WHERE user_id = p_user_id
      AND provider = 'email';
  END IF;

  IF v_new_name IS NOT NULL THEN
    VALUES (p_user_id, v_new_name)
    ON CONFLICT (user_id) DO UPDATE
      SET display_name = EXCLUDED.display_name,
          updated_at = now();
  END IF;

  PERFORM public._audit_log(
    'admin',
    v_uid,
    'tenant_admin_update',
    'tenant',
    p_tenant_id,
    format('Updated tenant admin %s.', p_user_id),
    jsonb_build_object('target_user_id', p_user_id)
  );

  RETURN true;
END; $$;


--
-- Name: rpc_admin_tenant_create(text, text, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_tenant_create(p_code text, p_short_label text, p_university text DEFAULT ''::text, p_department text DEFAULT ''::text) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_uid uuid; v_id uuid;
BEGIN
  v_uid := public._assert_super_admin();
  VALUES (trim(p_code), trim(p_short_label), COALESCE(trim(p_university),''), COALESCE(trim(p_department),''))
  RETURNING id INTO v_id;
  PERFORM public._audit_log('admin', v_uid, 'tenant_create', 'tenant', v_id,
    format('Created tenant %s (%s).', trim(p_short_label), trim(p_code)), jsonb_build_object('code', trim(p_code)));
  RETURN v_id;
END; $$;


--
-- Name: rpc_admin_tenant_list(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_tenant_list() RETURNS TABLE(id uuid, code text, short_label text, university text, department text, status text, created_at timestamp with time zone, updated_at timestamp with time zone, tenant_admins jsonb, pending_applications jsonb)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
BEGIN
  PERFORM public._assert_super_admin();
  RETURN QUERY
  SELECT
    t.id,
    t.code,
    t.short_label,
    t.university,
    t.department,
    t.status,
    t.created_at,
    t.updated_at,
    COALESCE((
      SELECT jsonb_agg(
        jsonb_build_object(
          'user_id', u.id,
          'name', COALESCE(
            NULLIF(trim(ap.display_name), ''),
            NULLIF(trim(u.raw_user_meta_data->>'name'), ''),
            lower(trim(u.email))
          ),
          'email', lower(trim(u.email)),
          'status', 'approved',
          'updated_at', COALESCE(ap.updated_at, u.updated_at, tam.updated_at, t.updated_at)
        )
        ORDER BY COALESCE(NULLIF(trim(ap.display_name), ''), lower(trim(u.email)))
      )
      FROM tenant_admin_memberships tam
      JOIN auth.users u ON u.id = tam.user_id
      LEFT JOIN admin_profiles ap ON ap.user_id = u.id
      WHERE tam.tenant_id = t.id
        AND tam.role = 'tenant_admin'
        AND u.email IS NOT NULL
        AND trim(u.email) <> ''
    ), '[]'::jsonb) AS tenant_admins,
    COALESCE((
      SELECT jsonb_agg(
        jsonb_build_object(
          'application_id', a.id,
          'name', a.applicant_name,
          'email', a.applicant_email,
          'status', 'pending',
          'created_at', a.created_at
        )
        ORDER BY a.created_at ASC
      )
      FROM tenant_admin_applications a
      WHERE a.tenant_id = t.id
        AND a.status = 'pending'
    ), '[]'::jsonb) AS pending_applications
  FROM tenants t
  ORDER BY t.code;
END; $$;


--
-- Name: rpc_admin_tenant_list_public(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_tenant_list_public() RETURNS TABLE(id uuid, code text, short_label text, university text, department text)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
BEGIN
  -- No auth check: this RPC is intentionally public so the registration
  -- form can display available departments before the user signs up.
  RETURN QUERY SELECT t.id, t.code, t.short_label, t.university, t.department FROM tenants t WHERE t.status = 'active' ORDER BY t.code;
END; $$;


--
-- Name: rpc_admin_tenant_update(uuid, text, text, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_tenant_update(p_tenant_id uuid, p_short_label text DEFAULT NULL::text, p_university text DEFAULT NULL::text, p_department text DEFAULT NULL::text, p_status text DEFAULT NULL::text) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_uid uuid;
BEGIN
  v_uid := public._assert_super_admin();
  UPDATE tenants SET short_label = COALESCE(NULLIF(trim(p_short_label),''), short_label),
    university = COALESCE(p_university, university), department = COALESCE(p_department, department),
    status = COALESCE(NULLIF(trim(p_status),''), status) WHERE id = p_tenant_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'tenant_not_found'; END IF;
  PERFORM public._audit_log('admin', v_uid, 'tenant_update', 'tenant', p_tenant_id, format('Updated tenant %s.', p_tenant_id), NULL);
  RETURN true;
END; $$;


--
-- Name: rpc_admin_update_juror(uuid, text, text, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_update_juror(p_juror_id uuid, p_juror_name text, p_juror_inst text, p_admin_password text, p_rpc_secret text DEFAULT ''::text) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
BEGIN
  IF NOT public._verify_admin_password(p_admin_password, p_rpc_secret) THEN RAISE EXCEPTION 'unauthorized' USING ERRCODE = 'P0401'; END IF;
  IF trim(coalesce(p_juror_name,'')) = '' OR trim(coalesce(p_juror_inst,'')) = '' THEN RAISE EXCEPTION 'invalid_juror'; END IF;
  UPDATE jurors SET juror_name = trim(p_juror_name), juror_inst = trim(p_juror_inst) WHERE id = p_juror_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'juror_not_found'; END IF;
  PERFORM public._audit_log('admin', null::uuid, 'juror_update', 'juror', p_juror_id, format('Admin updated juror %s.', trim(p_juror_name)), NULL);
  RETURN true;
END; $$;


--
-- Name: rpc_admin_update_semester(uuid, text, date, jsonb, jsonb, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_update_semester(p_semester_id uuid, p_semester_name text, p_poster_date date, p_criteria_template jsonb DEFAULT NULL::jsonb, p_mudek_template jsonb DEFAULT NULL::jsonb, p_admin_password text DEFAULT ''::text, p_rpc_secret text DEFAULT ''::text) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_name text; v_hs boolean := false;
BEGIN
  IF NOT public._verify_admin_password(p_admin_password, p_rpc_secret) THEN RAISE EXCEPTION 'unauthorized' USING ERRCODE = 'P0401'; END IF;
  v_name := trim(p_semester_name);
  IF v_name IS NULL OR v_name = '' THEN RAISE EXCEPTION 'semester_name_required'; END IF;
  IF EXISTS (SELECT 1 FROM semesters s WHERE lower(trim(s.semester_name)) = lower(v_name) AND s.id <> p_semester_id) THEN
    RAISE EXCEPTION 'semester_name_exists'; END IF;
  IF p_criteria_template IS NOT NULL OR p_mudek_template IS NOT NULL THEN
    IF EXISTS (SELECT 1 FROM semesters WHERE id = p_semester_id AND is_locked = TRUE) THEN RAISE EXCEPTION 'semester_template_locked_by_scores'; END IF;
    SELECT EXISTS (SELECT 1 FROM scores sc WHERE sc.semester_id = p_semester_id
      AND (sc.final_submitted_at IS NOT NULL OR (sc.criteria_scores IS NOT NULL AND sc.criteria_scores <> '{}'::jsonb))) INTO v_hs;
    IF v_hs THEN RAISE EXCEPTION 'semester_template_locked_by_scores'; END IF;
  END IF;
  UPDATE semesters SET semester_name = v_name, poster_date = p_poster_date,
    criteria_template = COALESCE(p_criteria_template, criteria_template), mudek_template = COALESCE(p_mudek_template, mudek_template)
  WHERE id = p_semester_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'semester_not_found'; END IF;
  PERFORM public._audit_log('admin', null::uuid, 'semester_update', 'semester', p_semester_id, format('Admin updated semester %s.', v_name), NULL);
  RETURN true;
END; $$;


--
-- Name: rpc_admin_upsert_project(uuid, integer, text, text, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_admin_upsert_project(p_semester_id uuid, p_group_no integer, p_project_title text, p_group_students text, p_admin_password text, p_rpc_secret text DEFAULT ''::text) RETURNS TABLE(project_id uuid)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE v_id uuid; v_tid uuid; v_cr boolean := false; v_act text; v_msg text; v_sn text; v_lk boolean := false;
BEGIN
  IF NOT public._verify_admin_password(p_admin_password, p_rpc_secret) THEN RAISE EXCEPTION 'unauthorized' USING ERRCODE = 'P0401'; END IF;
  SELECT semester_name, COALESCE(is_locked,false), tenant_id INTO v_sn, v_lk, v_tid FROM semesters WHERE id = p_semester_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'semester_not_found'; END IF;
  IF v_lk THEN RAISE EXCEPTION 'semester_locked'; END IF;
  SELECT id INTO v_id FROM projects WHERE semester_id = p_semester_id AND group_no = p_group_no LIMIT 1;
  IF v_id IS NULL THEN
    VALUES (p_semester_id, v_tid, p_group_no, p_project_title, p_group_students) RETURNING id INTO v_id;
    v_cr := true;
  ELSE
    UPDATE projects SET project_title = p_project_title, group_students = p_group_students WHERE id = v_id;
  END IF;
  v_act := CASE WHEN v_cr THEN 'project_create' ELSE 'project_update' END;
  v_msg := format('Admin %s project Group %s — %s (%s).', CASE WHEN v_cr THEN 'created' ELSE 'updated' END, p_group_no, p_project_title, COALESCE(v_sn, p_semester_id::text));
  PERFORM public._audit_log('admin', null::uuid, v_act, 'project', v_id, v_msg,
    jsonb_build_object('semester_id', p_semester_id, 'group_no', p_group_no, 'semester_name', v_sn));
  RETURN QUERY SELECT v_id;
END; $$;


--
-- Name: rpc_create_or_get_juror_and_issue_pin(uuid, text, text, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_create_or_get_juror_and_issue_pin(p_semester_id uuid, p_juror_name text, p_juror_inst text, p_force_reissue boolean DEFAULT false) RETURNS TABLE(juror_id uuid, juror_name text, juror_inst text, needs_pin boolean, pin_plain_once text, locked_until timestamp with time zone, failed_attempts integer)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
#variable_conflict use_column
DECLARE
  v_norm_name       text;
  v_norm_inst       text;
  v_juror_id        uuid;
  v_juror_name      text;
  v_juror_inst      text;
  v_pin             text;
  v_pin_hash        text;
  v_exists          boolean;
  v_constraint      text;
  v_locked_until    timestamptz;
  v_failed_attempts integer;
  v_pin_plain_once  text;
  v_secret          text;
  v_reveal_pending  boolean := false;
  v_tenant_id       uuid;
BEGIN
  v_norm_name := lower(regexp_replace(trim(coalesce(p_juror_name, '')), '\s+', ' ', 'g'));
  v_norm_inst := lower(regexp_replace(trim(coalesce(p_juror_inst, '')), '\s+', ' ', 'g'));

  PERFORM pg_advisory_xact_lock(hashtext(v_norm_name || '|' || v_norm_inst));

  -- Look up tenant_id from the semester (needed for juror_semester_auth rows)
  SELECT s.tenant_id INTO v_tenant_id
  FROM semesters s
  WHERE s.id = p_semester_id
    AND s.is_current = true;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'semester_inactive';
  END IF;

  IF v_norm_name = '' OR v_norm_inst = '' THEN
    RAISE EXCEPTION 'invalid juror identity';
  END IF;

  SELECT j.id, j.juror_name, j.juror_inst
    INTO v_juror_id, v_juror_name, v_juror_inst
  FROM jurors j
  WHERE lower(regexp_replace(trim(coalesce(j.juror_name, '')), '\s+', ' ', 'g')) = v_norm_name
    AND lower(regexp_replace(trim(coalesce(j.juror_inst, '')), '\s+', ' ', 'g')) = v_norm_inst
  ORDER BY j.id
  LIMIT 1;

  IF v_juror_id IS NULL THEN
    BEGIN
      VALUES (trim(p_juror_name), trim(p_juror_inst))
      RETURNING id, juror_name, juror_inst
      INTO v_juror_id, v_juror_name, v_juror_inst;
    EXCEPTION WHEN unique_violation THEN
      GET STACKED DIAGNOSTICS v_constraint = CONSTRAINT_NAME;
      IF v_constraint = 'jurors_name_inst_norm_uniq' THEN
        SELECT j.id, j.juror_name, j.juror_inst
          INTO v_juror_id, v_juror_name, v_juror_inst
        FROM jurors j
        WHERE lower(regexp_replace(trim(coalesce(j.juror_name, '')), '\s+', ' ', 'g')) = v_norm_name
          AND lower(regexp_replace(trim(coalesce(j.juror_inst, '')), '\s+', ' ', 'g')) = v_norm_inst
        ORDER BY j.id
        LIMIT 1;
      ELSE
        RAISE;
      END IF;
    END;
  END IF;

  SELECT true INTO v_exists
  FROM juror_semester_auth a
  WHERE a.juror_id = v_juror_id
    AND a.semester_id = p_semester_id
  LIMIT 1;

  IF v_exists THEN
    SELECT a.locked_until, a.failed_attempts, a.pin_plain_once, a.pin_reveal_pending
      INTO v_locked_until, v_failed_attempts, v_pin_plain_once, v_reveal_pending
    FROM juror_semester_auth a
    WHERE a.juror_id = v_juror_id
      AND a.semester_id = p_semester_id
    LIMIT 1;

    -- Pending reveal takes priority: surface it regardless of force_reissue.
    IF v_reveal_pending THEN
      IF v_pin_plain_once IS NOT NULL AND v_pin_plain_once LIKE 'enc:%' THEN
        SELECT decrypted_secret INTO v_secret
        FROM vault.decrypted_secrets
        WHERE name = 'pin_secret'
        LIMIT 1;
        IF v_secret IS NULL OR v_secret = '' THEN
          RAISE EXCEPTION 'pin_secret_missing';
        END IF;
        v_pin_plain_once := pgp_sym_decrypt(
          decode(substring(v_pin_plain_once from 5), 'base64'),
          v_secret
        );
      END IF;
      IF v_pin_plain_once IS NULL THEN
        -- pin_plain_once missing despite pin_reveal_pending=true (data corruption).
        -- Generate a new PIN silently and log the recovery for admin forensics.
        PERFORM public._audit_log(
          'system', null::uuid, 'pin_recovery_regen',
          'juror_semester_auth', v_juror_id,
          format('pin_plain_once missing on reveal for juror %s — new PIN generated', v_juror_id),
          jsonb_build_object(
            'juror_id', v_juror_id,
            'semester_id', p_semester_id,
            'reason', 'pin_plain_once_null_on_reveal'
          )
        );
        v_pin := lpad((('x' || encode(gen_random_bytes(2), 'hex'))::bit(16)::int % 10000)::text, 4, '0');
        v_pin_hash := crypt(v_pin, gen_salt('bf'::text));
        v_pin_plain_once := v_pin;
        UPDATE juror_semester_auth
        SET pin_hash = v_pin_hash,
            failed_attempts = 0,
            locked_until = null,
            pin_reveal_pending = false,
            pin_plain_once = null
        WHERE juror_id = v_juror_id
          AND semester_id = p_semester_id;
      ELSE
        UPDATE juror_semester_auth
        SET failed_attempts = 0,
            locked_until = null,
            pin_reveal_pending = false,
            pin_plain_once = null
        WHERE juror_id = v_juror_id
          AND semester_id = p_semester_id;
      END IF;

      RETURN QUERY SELECT null::uuid, v_juror_name, v_juror_inst, false, v_pin_plain_once,
        null::timestamptz, 0;
      RETURN;
    END IF;

    -- Force-reissue: reset PIN, scores, and final_submitted_at so the caller
    -- gets a clean slate. Used by demo mode so each visitor starts fresh.
    IF p_force_reissue THEN
      v_pin      := lpad((('x' || encode(gen_random_bytes(2), 'hex'))::bit(16)::int % 10000)::text, 4, '0');
      v_pin_hash := crypt(v_pin, gen_salt('bf'::text));
      UPDATE juror_semester_auth
      SET pin_hash        = v_pin_hash,
          failed_attempts = 0,
          locked_until    = null,
          pin_reveal_pending = false,
          pin_plain_once  = null,
          edit_enabled    = false
      WHERE juror_id   = v_juror_id
        AND semester_id = p_semester_id;
      -- Clear all scores so the next demo user starts with a blank evaluation
      UPDATE scores
      SET criteria_scores    = NULL,
          comment            = NULL,
          final_submitted_at = NULL
      WHERE juror_id   = v_juror_id
        AND semester_id = p_semester_id;
      RETURN QUERY SELECT null::uuid, v_juror_name, v_juror_inst, false, v_pin,
        null::timestamptz, 0;
      RETURN;
    END IF;

    RETURN QUERY SELECT null::uuid, v_juror_name, v_juror_inst, true, null::text,
      v_locked_until, coalesce(v_failed_attempts, 0);
    RETURN;
  END IF;

  v_pin      := lpad((('x' || encode(gen_random_bytes(2), 'hex'))::bit(16)::int % 10000)::text, 4, '0');
  v_pin_hash := crypt(v_pin, gen_salt('bf'::text));

  VALUES (v_juror_id, p_semester_id, v_pin_hash, v_tenant_id)
  ON CONFLICT (juror_id, semester_id) DO NOTHING;

  IF NOT FOUND THEN
    RETURN QUERY SELECT null::uuid, v_juror_name, v_juror_inst, true, null::text,
      null::timestamptz, 0;
    RETURN;
  END IF;

  RETURN QUERY SELECT null::uuid, v_juror_name, v_juror_inst, false, v_pin,
    null::timestamptz, 0;
END;
$$;


--
-- Name: rpc_finalize_juror_submission(uuid, uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_finalize_juror_submission(p_semester_id uuid, p_juror_id uuid, p_session_token text) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE
  v_total int := 0;
  v_completed int := 0;
  v_now timestamptz := now();
  v_juror_name text;
  v_sem_name   text;
  v_sem_locked boolean := false;
BEGIN
  PERFORM public._assert_juror_session(p_semester_id, p_juror_id, p_session_token);

  SELECT COALESCE(s.is_locked, false)
    INTO v_sem_locked
  FROM semesters s
  WHERE s.id = p_semester_id
    AND s.is_current = true;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'semester_inactive';
  END IF;

  IF v_sem_locked THEN
    RAISE EXCEPTION 'semester_locked';
  END IF;

  SELECT COUNT(*)::int INTO v_total
  FROM projects p
  WHERE p.semester_id = p_semester_id;

  SELECT COUNT(*)::int INTO v_completed
  FROM scores sc
  WHERE sc.semester_id = p_semester_id
    AND sc.juror_id = p_juror_id
    AND sc.criteria_scores IS NOT NULL
    AND sc.criteria_scores <> '{}'::jsonb;

  IF v_total = 0 OR v_completed < v_total THEN
    RETURN false;
  END IF;

  UPDATE juror_semester_auth
  SET edit_enabled = false
  WHERE juror_id = p_juror_id
    AND semester_id = p_semester_id;

  -- Stamp final submission time for all score rows (server time)
  UPDATE scores
  SET final_submitted_at = v_now
  WHERE juror_id = p_juror_id
    AND semester_id = p_semester_id;

  SELECT juror_name INTO v_juror_name FROM jurors WHERE id = p_juror_id;
  SELECT semester_name INTO v_sem_name FROM semesters WHERE id = p_semester_id;
  PERFORM public._audit_log(
    'juror',
    p_juror_id,
    'juror_finalize_submission',
    'semester',
    p_semester_id,
    format('Juror %s finalized submission (%s).', COALESCE(v_juror_name, p_juror_id::text), COALESCE(v_sem_name, p_semester_id::text)),
    null
  );

  RETURN true;
END;
$$;


--
-- Name: rpc_get_current_semester(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_get_current_semester() RETURNS TABLE(id uuid, semester_name text, is_current boolean, is_locked boolean, poster_date date, university text, department text)
    LANGUAGE sql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
  SELECT s.id, s.semester_name, s.is_current, s.is_locked, s.poster_date,
         t.university, t.department
  FROM semesters s
  LEFT JOIN tenants t ON t.id = s.tenant_id
  WHERE s.is_current = true
  LIMIT 1;
$$;


--
-- Name: rpc_get_juror_edit_state(uuid, uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_get_juror_edit_state(p_semester_id uuid, p_juror_id uuid, p_session_token text) RETURNS TABLE(edit_enabled boolean, edit_allowed boolean, lock_active boolean)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE
  v_lock boolean := false;
  v_enabled boolean := false;
  v_sem_current boolean := false;
BEGIN
  PERFORM public._assert_juror_session(p_semester_id, p_juror_id, p_session_token);

  SELECT s.is_current, COALESCE(s.is_locked, false)
    INTO v_sem_current, v_lock
  FROM semesters s
  WHERE s.id = p_semester_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT false, false, false;
    RETURN;
  END IF;

  -- If semester is not current, signal a lock to the frontend
  IF NOT v_sem_current THEN
    RETURN QUERY SELECT false, false, true;
    RETURN;
  END IF;

  SELECT a.edit_enabled
    INTO v_enabled
  FROM juror_semester_auth a
  WHERE a.juror_id = p_juror_id
    AND a.semester_id = p_semester_id;

  v_enabled := COALESCE(v_enabled, false);

  RETURN QUERY
    SELECT
      v_enabled,
      (v_enabled AND NOT v_lock),
      v_lock;
END;
$$;


--
-- Name: rpc_list_projects(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_list_projects(p_semester_id uuid, p_juror_id uuid) RETURNS TABLE(project_id uuid, group_no integer, project_title text, group_students text, poster_date date, criteria_scores jsonb, total integer, comment text, updated_at timestamp with time zone, final_submitted_at timestamp with time zone)
    LANGUAGE sql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
  SELECT
    p.id             AS project_id,
    p.group_no,
    p.project_title,
    p.group_students,
    COALESCE(s.poster_date, sem.poster_date) AS poster_date,
    s.criteria_scores,
    s.total,
    s.comment,
    s.updated_at,
    s.final_submitted_at
  FROM projects p
  JOIN semesters sem
    ON sem.id = p.semester_id
  LEFT JOIN scores s
    ON  s.project_id  = p.id
    AND s.semester_id = p_semester_id
    AND s.juror_id    = p_juror_id
  WHERE p.semester_id = p_semester_id
  ORDER BY p.group_no;
$$;


--
-- Name: rpc_list_semesters(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_list_semesters() RETURNS TABLE(id uuid, semester_name text, is_current boolean, is_locked boolean, poster_date date, updated_at timestamp with time zone, criteria_template jsonb, mudek_template jsonb, university text, department text)
    LANGUAGE sql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
  SELECT
    s.id, s.semester_name, s.is_current, s.is_locked,
    s.poster_date, s.updated_at, s.criteria_template, s.mudek_template,
    t.university, t.department
  FROM semesters s
  LEFT JOIN tenants t ON t.id = s.tenant_id
  ORDER BY s.poster_date DESC NULLS LAST;
$$;


--
-- Name: rpc_upsert_score(uuid, uuid, uuid, text, jsonb, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_upsert_score(p_semester_id uuid, p_project_id uuid, p_juror_id uuid, p_session_token text, p_criteria_scores jsonb, p_comment text) RETURNS integer
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE
  v_total          integer;
  v_template       jsonb;
  v_crit           jsonb;
  v_key            text;
  v_max            integer;
  v_val            text;
  v_prev           scores%ROWTYPE;
  v_had_any        boolean := false;
  v_had_complete   boolean := false;
  v_now_any        boolean := false;
  v_now_complete   boolean := false;
  v_completed_before integer := 0;
  v_completed_after  integer := 0;
  v_total_projects   integer := 0;
  v_before_all     boolean := false;
  v_after_all      boolean := false;
  v_group_no       integer;
  v_project_title  text;
  v_juror_name     text;
  v_sem_name       text;
  v_new_cs         jsonb;
  v_new_comment    text;
  v_sem_locked     boolean := false;
  v_sem_current    boolean := false;
  v_tenant_id      uuid;
BEGIN
  -- Look up semester state and tenant_id
  SELECT COALESCE(s.is_locked, false), COALESCE(s.is_current, false), s.tenant_id
    INTO v_sem_locked, v_sem_current, v_tenant_id
  FROM semesters s
  WHERE s.id = p_semester_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'semester_not_found';
  END IF;

  IF v_sem_locked OR NOT v_sem_current THEN
    RAISE EXCEPTION 'semester_locked';
  END IF;

  PERFORM public._assert_juror_session(p_semester_id, p_juror_id, p_session_token);

  -- Validate p_criteria_scores against semester template
  SELECT criteria_template INTO v_template
  FROM semesters WHERE id = p_semester_id;

  IF v_template IS NOT NULL AND jsonb_array_length(v_template) > 0 THEN
    -- Check each template criterion: value must be in [0, max] if provided
    FOR v_crit IN SELECT * FROM jsonb_array_elements(v_template) LOOP
      v_key := v_crit->>'key';
      v_max := (v_crit->>'max')::integer;
      v_val := p_criteria_scores->>v_key;
      IF v_val IS NOT NULL
         AND (v_val::integer < 0 OR v_val::integer > v_max) THEN
        RAISE EXCEPTION 'criteria_score_out_of_range' USING HINT = v_key;
      END IF;
    END LOOP;
    -- Reject keys in input that are absent from the template
    FOR v_key IN SELECT jsonb_object_keys(p_criteria_scores) LOOP
      IF NOT EXISTS (
        SELECT 1 FROM jsonb_array_elements(v_template) t
        WHERE t->>'key' = v_key
      ) THEN
        RAISE EXCEPTION 'criteria_key_unknown' USING HINT = v_key;
      END IF;
    END LOOP;
  END IF;

  SELECT group_no, project_title
    INTO v_group_no, v_project_title
  FROM projects
  WHERE id = p_project_id;

  SELECT juror_name INTO v_juror_name
  FROM jurors
  WHERE id = p_juror_id;

  SELECT semester_name INTO v_sem_name
  FROM semesters
  WHERE id = p_semester_id;

  SELECT * INTO v_prev
  FROM scores
  WHERE semester_id = p_semester_id
    AND project_id  = p_project_id
    AND juror_id    = p_juror_id;

  IF FOUND THEN
    -- had_any: previous criteria_scores had at least one value, or had a comment
    v_had_any := (
      (v_prev.criteria_scores IS NOT NULL
       AND v_prev.criteria_scores <> '{}'::jsonb)
      OR NULLIF(trim(coalesce(v_prev.comment, '')), '') IS NOT NULL
    );
    -- had_complete: all template keys present and non-null in previous scores
    v_had_complete := (
      v_prev.criteria_scores IS NOT NULL
      AND v_template IS NOT NULL
      AND jsonb_array_length(v_template) > 0
      AND (
        SELECT bool_and(v_prev.criteria_scores->>(t->>'key') IS NOT NULL)
        FROM jsonb_array_elements(v_template) t
      )
    );
  END IF;

  SELECT COUNT(*)::int INTO v_total_projects
  FROM projects
  WHERE semester_id = p_semester_id;

  -- Count previously completed groups for this juror
  SELECT COUNT(*)::int INTO v_completed_before
  FROM scores sc
  WHERE sc.semester_id = p_semester_id
    AND sc.juror_id = p_juror_id
    AND sc.criteria_scores IS NOT NULL
    AND sc.criteria_scores <> '{}'::jsonb
    AND (
      SELECT bool_and(sc.criteria_scores->>(t->>'key') IS NOT NULL)
      FROM jsonb_array_elements(COALESCE(v_template, '[]'::jsonb)) t
    );

  -- Insert with tenant_id looked up from the semester
    semester_id, project_id, juror_id,
    criteria_scores, comment, tenant_id
  )
  VALUES (
    p_semester_id, p_project_id, p_juror_id,
    p_criteria_scores, p_comment, v_tenant_id
  )
  ON CONFLICT (semester_id, project_id, juror_id)
  DO UPDATE SET
    criteria_scores = EXCLUDED.criteria_scores,
    comment         = EXCLUDED.comment
  RETURNING total INTO v_total;

  SELECT criteria_scores, comment
    INTO v_new_cs, v_new_comment
  FROM scores
  WHERE semester_id = p_semester_id
    AND project_id  = p_project_id
    AND juror_id    = p_juror_id;

  v_now_any := (
    (v_new_cs IS NOT NULL AND v_new_cs <> '{}'::jsonb)
    OR NULLIF(trim(coalesce(v_new_comment, '')), '') IS NOT NULL
  );
  -- now_complete: all template keys present and non-null
  v_now_complete := (
    v_new_cs IS NOT NULL
    AND v_template IS NOT NULL
    AND jsonb_array_length(v_template) > 0
    AND (
      SELECT bool_and(v_new_cs->>(t->>'key') IS NOT NULL)
      FROM jsonb_array_elements(v_template) t
    )
  );

  SELECT COUNT(*)::int INTO v_completed_after
  FROM scores sc
  WHERE sc.semester_id = p_semester_id
    AND sc.juror_id = p_juror_id
    AND sc.criteria_scores IS NOT NULL
    AND sc.criteria_scores <> '{}'::jsonb
    AND (
      SELECT bool_and(sc.criteria_scores->>(t->>'key') IS NOT NULL)
      FROM jsonb_array_elements(COALESCE(v_template, '[]'::jsonb)) t
    );

  v_before_all := (v_total_projects > 0 AND v_completed_before = v_total_projects);
  v_after_all := (v_total_projects > 0 AND v_completed_after = v_total_projects);

  IF (NOT v_had_any) AND v_now_any THEN
    PERFORM public._audit_log(
      'juror',
      p_juror_id,
      'juror_group_started',
      'project',
      p_project_id,
      format(
        'Juror %s started evaluating Group %s (%s).',
        COALESCE(v_juror_name, p_juror_id::text),
        COALESCE(v_group_no::text, '?'),
        COALESCE(v_sem_name, p_semester_id::text)
      ),
      jsonb_build_object(
        'semester_id', p_semester_id,
        'semester_name', v_sem_name,
        'group_no', v_group_no,
        'project_title', v_project_title
      )
    );
  END IF;

  IF (NOT v_had_complete) AND v_now_complete THEN
    PERFORM public._audit_log(
      'juror',
      p_juror_id,
      'juror_group_completed',
      'project',
      p_project_id,
      format(
        'Juror %s completed evaluation for Group %s (%s).',
        COALESCE(v_juror_name, p_juror_id::text),
        COALESCE(v_group_no::text, '?'),
        COALESCE(v_sem_name, p_semester_id::text)
      ),
      jsonb_build_object(
        'semester_id', p_semester_id,
        'semester_name', v_sem_name,
        'group_no', v_group_no,
        'project_title', v_project_title
      )
    );
  END IF;

  IF (NOT v_before_all) AND v_after_all THEN
    PERFORM public._audit_log(
      'juror',
      p_juror_id,
      'juror_all_completed',
      'semester',
      p_semester_id,
      format(
        'Juror %s completed all project evaluations (%s).',
        COALESCE(v_juror_name, p_juror_id::text),
        COALESCE(v_sem_name, p_semester_id::text)
      ),
      jsonb_build_object(
        'semester_id', p_semester_id,
        'semester_name', v_sem_name,
        'completed_projects', v_completed_after,
        'total_projects', v_total_projects
      )
    );
  END IF;

  RETURN v_total;
END;
$$;


--
-- Name: rpc_verify_juror_pin(uuid, text, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_verify_juror_pin(p_semester_id uuid, p_juror_name text, p_juror_inst text, p_pin text) RETURNS TABLE(ok boolean, juror_id uuid, juror_name text, juror_inst text, error_code text, locked_until timestamp with time zone, failed_attempts integer, pin_plain_once text, session_token text)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
#variable_conflict use_column
DECLARE
  v_norm_name text;
  v_norm_inst text;
  v_pin text;
  v_now timestamptz := now();
  v_juror_id uuid;
  v_juror_name text;
  v_juror_inst text;
  v_auth juror_semester_auth%ROWTYPE;
  v_failed integer;
  v_locked timestamptz;
  v_sem_name text;
  v_pin_plain_once text;
  v_secret text;
  v_session_token text;
BEGIN
  v_norm_name := lower(regexp_replace(trim(coalesce(p_juror_name, '')), '\\s+', ' ', 'g'));
  v_norm_inst := lower(regexp_replace(trim(coalesce(p_juror_inst, '')), '\\s+', ' ', 'g'));
  v_pin := regexp_replace(coalesce(p_pin, ''), '\\s+', '', 'g');

  IF NOT EXISTS (
    SELECT 1 FROM semesters s
    WHERE s.id = p_semester_id
      AND s.is_current = true
  ) THEN
    RETURN QUERY SELECT false, null::uuid, null::text, null::text, 'semester_inactive', null::timestamptz, 0, null::text, null::text;
    RETURN;
  END IF;

  SELECT j.id, j.juror_name, j.juror_inst
    INTO v_juror_id, v_juror_name, v_juror_inst
  FROM jurors j
  WHERE lower(regexp_replace(trim(coalesce(j.juror_name, '')), '\\s+', ' ', 'g')) = v_norm_name
    AND lower(regexp_replace(trim(coalesce(j.juror_inst, '')), '\\s+', ' ', 'g')) = v_norm_inst
  ORDER BY j.id
  LIMIT 1;

  IF v_juror_id IS NULL THEN
    RETURN QUERY SELECT false, null::uuid, null::text, null::text, 'not_found', null::timestamptz, 0, null::text, null::text;
    RETURN;
  END IF;

  SELECT *
    INTO v_auth
  FROM juror_semester_auth a
  WHERE a.juror_id = v_juror_id
    AND a.semester_id = p_semester_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT false, v_juror_id, v_juror_name, v_juror_inst, 'no_pin', null::timestamptz, 0, null::text, null::text;
    RETURN;
  END IF;

  IF v_auth.locked_until IS NOT NULL AND v_auth.locked_until > v_now THEN
    RETURN QUERY SELECT false, v_juror_id, v_juror_name, v_juror_inst, 'locked', v_auth.locked_until, v_auth.failed_attempts, null::text, null::text;
    RETURN;
  END IF;

  -- Lock window expired: reset attempts so the next failure starts from 1 again.
  IF v_auth.locked_until IS NOT NULL AND v_auth.locked_until <= v_now THEN
    UPDATE juror_semester_auth
    SET failed_attempts = 0,
        locked_until = null
    WHERE id = v_auth.id;
    v_auth.failed_attempts := 0;
    v_auth.locked_until := null;
  END IF;

  IF crypt(v_pin, v_auth.pin_hash) = v_auth.pin_hash THEN
    v_pin_plain_once := null::text;
    IF v_auth.pin_reveal_pending AND v_auth.pin_plain_once IS NOT NULL THEN
      IF v_auth.pin_plain_once LIKE 'enc:%' THEN
        SELECT decrypted_secret INTO v_secret
        FROM vault.decrypted_secrets
        WHERE name = 'pin_secret'
        LIMIT 1;
        IF v_secret IS NULL OR v_secret = '' THEN
          RAISE EXCEPTION 'pin_secret_missing';
        END IF;
        v_pin_plain_once := pgp_sym_decrypt(
          decode(substring(v_auth.pin_plain_once from 5), 'base64'),
          v_secret
        );
      ELSE
        v_pin_plain_once := v_auth.pin_plain_once;
      END IF;
    END IF;
    v_session_token := encode(gen_random_bytes(32), 'hex');
    UPDATE juror_semester_auth
    SET last_seen_at = v_now,
        failed_attempts = 0,
        locked_until = null,
        pin_reveal_pending = false,
        pin_plain_once = null,
        session_token_hash = crypt(v_session_token, gen_salt('bf')),
        session_expires_at = v_now + interval '12 hours'
    WHERE id = v_auth.id;

    RETURN QUERY SELECT true, v_juror_id, v_juror_name, v_juror_inst, null::text, null::timestamptz, 0, v_pin_plain_once, v_session_token;
    RETURN;
  END IF;

  v_failed := v_auth.failed_attempts + 1;
  v_locked := null;
  IF v_failed >= 3 THEN
    v_locked := v_now + interval '15 minutes';
  END IF;

  UPDATE juror_semester_auth
  SET failed_attempts = v_failed,
      locked_until = v_locked
  WHERE id = v_auth.id;

  -- Log every failed attempt (not only lockout) for poster-day forensics.
  SELECT semester_name INTO v_sem_name FROM semesters WHERE id = p_semester_id;
  PERFORM public._audit_log(
    'juror',
    v_juror_id,
    CASE WHEN v_locked IS NOT NULL THEN 'juror_pin_locked' ELSE 'juror_pin_failed' END,
    'juror',
    v_juror_id,
    format(
      CASE WHEN v_locked IS NOT NULL
        THEN 'Juror %s PIN locked after too many failed attempts.'
        ELSE 'Juror %s failed PIN attempt %s/3.'
      END,
      COALESCE(v_juror_name, v_juror_id::text),
      v_failed
    ),
    jsonb_build_object(
      'juror_name', v_juror_name,
      'juror_inst', v_juror_inst,
      'semester_id', p_semester_id,
      'semester_name', v_sem_name,
      'failed_attempts', v_failed,
      'locked_until', v_locked
    )
  );

  IF v_locked IS NOT NULL THEN
    RETURN QUERY SELECT false, v_juror_id, v_juror_name, v_juror_inst, 'locked', v_locked, v_failed, null::text, null::text;
  END IF;

  RETURN QUERY SELECT false, v_juror_id, v_juror_name, v_juror_inst, 'invalid', v_locked, v_failed, null::text, null::text;
END;
$$;


--
-- Name: rpc_verify_semester_entry_token(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_verify_semester_entry_token(p_token text) RETURNS TABLE(ok boolean, semester_id uuid, semester_name text, error_code text)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
DECLARE
  v_hash text;
  v_sem  public.semesters%ROWTYPE;
BEGIN
  v_hash := encode(extensions.digest(coalesce(p_token, ''), 'sha256'), 'hex');
  SELECT * INTO v_sem FROM public.semesters
  WHERE entry_token_hash = v_hash
    AND entry_token_enabled = true
    AND (entry_token_expires_at IS NULL OR entry_token_expires_at > now())
  LIMIT 1;
  IF NOT FOUND THEN
    RETURN QUERY SELECT false, null::uuid, null::text, 'invalid'::text;
    RETURN;
  END IF;
  RETURN QUERY SELECT true, v_sem.id, v_sem.semester_name, null::text;
END;
$$;


--
-- Name: trg_admin_profiles_set_updated_at(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.trg_admin_profiles_set_updated_at() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN NEW.updated_at = now(); RETURN NEW; END; $$;


--
-- Name: trg_audit_logs_immutable(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.trg_audit_logs_immutable() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  RAISE EXCEPTION 'audit_logs_immutable';
  RETURN OLD;
END;
$$;


--
-- Name: trg_jsa_enforce_tenant(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.trg_jsa_enforce_tenant() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_semester_tenant uuid;
BEGIN
  SELECT tenant_id INTO v_semester_tenant
  FROM semesters WHERE id = NEW.semester_id;

  IF v_semester_tenant IS NULL THEN
    RAISE EXCEPTION 'jsa_semester_not_found';
  END IF;

  IF NEW.tenant_id IS DISTINCT FROM v_semester_tenant THEN
    RAISE EXCEPTION 'jsa_tenant_mismatch'
      USING HINT = 'Juror auth tenant_id must match its semester tenant_id.';
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: trg_projects_enforce_tenant(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.trg_projects_enforce_tenant() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_semester_tenant uuid;
BEGIN
  SELECT tenant_id INTO v_semester_tenant
  FROM semesters WHERE id = NEW.semester_id;

  IF v_semester_tenant IS NULL THEN
    RAISE EXCEPTION 'project_semester_not_found'
      USING HINT = 'Semester does not exist.';
  END IF;

  IF NEW.tenant_id IS DISTINCT FROM v_semester_tenant THEN
    RAISE EXCEPTION 'project_tenant_mismatch'
      USING HINT = 'Project tenant_id must match its semester tenant_id.';
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: trg_scores_compute_total(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.trg_scores_compute_total() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_total numeric := 0;
  v_key   text;
  v_val   text;
BEGIN
  IF NEW.criteria_scores IS NULL
     OR NEW.criteria_scores = '{}'::jsonb THEN
    NEW.total := NULL;
    RETURN NEW;
  END IF;

  FOR v_key, v_val IN SELECT * FROM jsonb_each_text(NEW.criteria_scores) LOOP
    IF v_val IS NULL THEN
      NEW.total := NULL;
      RETURN NEW;
    END IF;
    v_total := v_total + (v_val::numeric);
  END LOOP;

  NEW.total := v_total::integer;
  RETURN NEW;
END;
$$;


--
-- Name: trg_scores_enforce_tenant(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.trg_scores_enforce_tenant() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_semester_tenant uuid;
  v_project_tenant  uuid;
BEGIN
  SELECT tenant_id INTO v_semester_tenant
  FROM semesters WHERE id = NEW.semester_id;

  IF v_semester_tenant IS NULL THEN
    RAISE EXCEPTION 'score_semester_not_found';
  END IF;

  SELECT tenant_id INTO v_project_tenant
  FROM projects WHERE id = NEW.project_id;

  IF v_project_tenant IS NULL THEN
    RAISE EXCEPTION 'score_project_not_found';
  END IF;

  IF NEW.tenant_id IS DISTINCT FROM v_semester_tenant THEN
    RAISE EXCEPTION 'score_tenant_mismatch_semester'
      USING HINT = 'Score tenant_id must match its semester tenant_id.';
  END IF;

  IF NEW.tenant_id IS DISTINCT FROM v_project_tenant THEN
    RAISE EXCEPTION 'score_tenant_mismatch_project'
      USING HINT = 'Score tenant_id must match its project tenant_id.';
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: trg_scores_set_poster_date(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.trg_scores_set_poster_date() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  SELECT poster_date INTO NEW.poster_date
  FROM semesters
  WHERE id = NEW.semester_id;
  RETURN NEW;
END;
$$;


--
-- Name: trg_scores_set_updated_at(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.trg_scores_set_updated_at() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF  NEW.criteria_scores IS DISTINCT FROM OLD.criteria_scores
   OR NEW.comment         IS DISTINCT FROM OLD.comment
  THEN
    NEW.updated_at := now();
  ELSE
    NEW.updated_at := OLD.updated_at;
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: trg_set_updated_at(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.trg_set_updated_at() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  NEW.updated_at := now();
  RETURN NEW;
END;
$$;


--
-- Name: trg_tenants_immutable_code(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.trg_tenants_immutable_code() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF OLD.code IS DISTINCT FROM NEW.code THEN
    RAISE EXCEPTION 'tenant_code_immutable'
      USING HINT = 'Tenant code cannot be changed after creation.';
  END IF;
  RETURN NEW;
END;
$$;


SET default_tablespace = '';

SET default_table_access_method = heap;

--
-- Name: admin_profiles; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.admin_profiles (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    user_id uuid NOT NULL,
    display_name text,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


--
-- Name: audit_logs; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.audit_logs (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    actor_type text NOT NULL,
    actor_id uuid,
    action text NOT NULL,
    entity_type text NOT NULL,
    entity_id uuid,
    message text NOT NULL,
    metadata jsonb,
    tenant_id uuid,
    CONSTRAINT audit_logs_actor_type_check CHECK ((actor_type = ANY (ARRAY['admin'::text, 'juror'::text, 'system'::text])))
);


--
-- Name: juror_semester_auth; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.juror_semester_auth (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    juror_id uuid NOT NULL,
    semester_id uuid NOT NULL,
    tenant_id uuid NOT NULL,
    pin_hash text NOT NULL,
    pin_reveal_pending boolean DEFAULT false NOT NULL,
    pin_plain_once text,
    edit_enabled boolean DEFAULT false NOT NULL,
    session_token_hash text,
    session_expires_at timestamp with time zone,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    failed_attempts integer DEFAULT 0 NOT NULL,
    locked_until timestamp with time zone,
    last_seen_at timestamp with time zone
);


--
-- Name: jurors; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.jurors (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    juror_name text NOT NULL,
    juror_inst text NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


--
-- Name: projects; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.projects (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    semester_id uuid NOT NULL,
    tenant_id uuid NOT NULL,
    group_no integer NOT NULL,
    project_title text NOT NULL,
    group_students text DEFAULT ''::text NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


--
-- Name: scores; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.scores (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    semester_id uuid NOT NULL,
    project_id uuid NOT NULL,
    juror_id uuid NOT NULL,
    tenant_id uuid NOT NULL,
    poster_date date,
    criteria_scores jsonb,
    total integer,
    comment text,
    final_submitted_at timestamp with time zone,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT scores_total_range CHECK (((total IS NULL) OR ((total >= 0) AND (total <= 100))))
);


--
-- Name: semesters; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.semesters (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    tenant_id uuid NOT NULL,
    semester_name text NOT NULL,
    is_current boolean DEFAULT false NOT NULL,
    is_locked boolean DEFAULT false NOT NULL,
    poster_date date,
    criteria_template jsonb DEFAULT '[]'::jsonb NOT NULL,
    mudek_template jsonb DEFAULT '[]'::jsonb NOT NULL,
    entry_token_hash text,
    entry_token_enabled boolean DEFAULT false NOT NULL,
    entry_token_created_at timestamp with time zone,
    entry_token_expires_at timestamp with time zone,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


--
-- Name: settings; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.settings (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    key text NOT NULL,
    tenant_id uuid,
    value text,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


--
-- Name: tenant_admin_applications; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.tenant_admin_applications (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    tenant_id uuid NOT NULL,
    applicant_email text NOT NULL,
    applicant_name text NOT NULL,
    university text DEFAULT ''::text NOT NULL,
    department text DEFAULT ''::text NOT NULL,
    status text DEFAULT 'pending'::text NOT NULL,
    reviewed_by uuid,
    reviewed_at timestamp with time zone,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    encrypted_password text,
    CONSTRAINT tenant_admin_applications_status_check CHECK ((status = ANY (ARRAY['pending'::text, 'approved'::text, 'rejected'::text, 'cancelled'::text])))
);


--
-- Name: tenant_admin_memberships; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.tenant_admin_memberships (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    tenant_id uuid,
    user_id uuid NOT NULL,
    role text DEFAULT 'tenant_admin'::text NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT tam_tenant_admin_requires_tenant CHECK (((role <> 'tenant_admin'::text) OR (tenant_id IS NOT NULL))),
    CONSTRAINT tenant_admin_memberships_role_check CHECK ((role = ANY (ARRAY['tenant_admin'::text, 'super_admin'::text])))
);


--
-- Name: tenants; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.tenants (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    code text NOT NULL,
    short_label text NOT NULL,
    university text DEFAULT ''::text NOT NULL,
    department text DEFAULT ''::text NOT NULL,
    status text DEFAULT 'active'::text NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT tenants_status_check CHECK ((status = ANY (ARRAY['active'::text, 'disabled'::text, 'archived'::text])))
);


