7a1131b1-7233-42d0-aed2-0651aa941abb	85b3df4b-b92f-47b7-84b6-b2a0a9b557c7	Spring 2026	t	f	2026-05-20	[{"key": "reaction_engineering", "max": 30, "blurb": "Evaluate kinetic modeling, reactor design rationale, and optimization of operating conditions.", "color": "#F59E0B", "label": "Reaction Engineering", "mudek": ["1.2", "2", "3.1"], "rubric": [{"max": 30, "min": 25, "desc": "Kinetics and reactor design rigorously analyzed", "level": "Superior", "range": "25–30"}, {"max": 24, "min": 19, "desc": "Correct kinetic analysis with well-chosen operating parameters", "level": "Proficient", "range": "19–24"}, {"max": 18, "min": 12, "desc": "Sound reaction analysis with minor omissions", "level": "Developing", "range": "12–18"}, {"max": 11, "min": 6, "desc": "Basic kinetics applied without optimization", "level": "Novice", "range": "6–11"}, {"max": 5, "min": 0, "desc": "Reaction analysis missing or incorrect", "level": "Unsatisfactory", "range": "0–5"}], "shortLabel": "Reaction", "mudek_outcomes": ["po_1_2", "po_2", "po_3_1"]}, {"key": "lab_technique", "max": 25, "blurb": "Assess experimental precision, reproducibility of results, and proper use of lab equipment.", "color": "#22C55E", "label": "Lab Technique", "mudek": ["5", "4"], "rubric": [{"max": 25, "min": 21, "desc": "Precise technique with reproducible results", "level": "Superior", "range": "21–25"}, {"max": 20, "min": 16, "desc": "Consistent lab results with good reproducibility across runs", "level": "Proficient", "range": "16–20"}, {"max": 15, "min": 10, "desc": "Competent lab work with acceptable accuracy", "level": "Developing", "range": "10–15"}, {"max": 9, "min": 5, "desc": "Lab work completed but lacks precision", "level": "Novice", "range": "5–9"}, {"max": 4, "min": 0, "desc": "Poor technique leading to unreliable data", "level": "Unsatisfactory", "range": "0–4"}], "shortLabel": "Lab", "mudek_outcomes": ["po_5", "po_4"]}, {"key": "safety_review", "max": 20, "blurb": "Evaluate SDS review completeness, risk assessment methodology, and safety protocol adherence.", "color": "#3B82F6", "label": "Safety Review", "mudek": ["6", "7"], "rubric": [{"max": 20, "min": 17, "desc": "Comprehensive SDS review and risk assessment done", "level": "Superior", "range": "17–20"}, {"max": 16, "min": 13, "desc": "Solid hazard review covering major risk scenarios systematically", "level": "Proficient", "range": "13–16"}, {"max": 12, "min": 8, "desc": "Adequate safety protocols identified", "level": "Developing", "range": "8–12"}, {"max": 7, "min": 4, "desc": "Basic safety awareness but gaps in protocol", "level": "Novice", "range": "4–7"}, {"max": 3, "min": 0, "desc": "Safety considerations absent", "level": "Unsatisfactory", "range": "0–3"}], "shortLabel": "Safety", "mudek_outcomes": ["po_6", "po_7"]}, {"key": "comm_skills", "max": 25, "blurb": "Assess written report quality, oral presentation confidence, and technical figure clarity.", "color": "#EF4444", "label": "Communication Skills", "mudek": ["9.1", "9.2"], "rubric": [{"max": 25, "min": 21, "desc": "Professional report and confident oral delivery", "level": "Superior", "range": "21–25"}, {"max": 20, "min": 16, "desc": "Well-written report with clear figures and confident delivery", "level": "Proficient", "range": "16–20"}, {"max": 15, "min": 10, "desc": "Clear writing and adequate presentation", "level": "Developing", "range": "10–15"}, {"max": 9, "min": 5, "desc": "Communication functional but unpolished", "level": "Novice", "range": "5–9"}, {"max": 4, "min": 0, "desc": "Written and oral delivery both weak", "level": "Unsatisfactory", "range": "0–4"}], "shortLabel": "Comm", "mudek_outcomes": ["po_9_1", "po_9_2"]}]	[{"id": "po_1_2", "code": "1.2", "desc_en": "Ability to apply knowledge of mathematics, natural sciences, fundamental engineering, computation, and discipline-specific topics to solve complex engineering problems.", "desc_tr": "Matematik, fen bilimleri, temel mühendislik, bilgisayarla hesaplama ve ilgili mühendislik disiplinine özgü konulardaki bilgileri, karmaşık mühendislik problemlerinin çözümünde kullanabilme becerisi."}, {"id": "po_2", "code": "2", "desc_en": "Ability to identify, formulate, and analyse complex engineering problems using fundamental science, mathematics, and engineering knowledge.", "desc_tr": "Karmaşık mühendislik problemlerini, temel bilim, matematik ve mühendislik bilgilerini kullanarak tanımlama, formüle etme ve analiz becerisi."}, {"id": "po_3_1", "code": "3.1", "desc_en": "Ability to design creative solutions to complex engineering problems.", "desc_tr": "Karmaşık mühendislik problemlerine yaratıcı çözümler tasarlama becerisi."}, {"id": "po_4", "code": "4", "desc_en": "Ability to select and use appropriate techniques, resources, and modern engineering and IT tools for complex engineering problems.", "desc_tr": "Karmaşık mühendislik problemlerinin analizi ve çözümüne yönelik uygun teknikleri, kaynakları ve modern araçları seçme ve kullanma becerisi."}, {"id": "po_5", "code": "5", "desc_en": "Ability to use research methods including literature review, experiment design, data collection, and analysis.", "desc_tr": "Literatür araştırması, deney tasarlama, veri toplama, sonuçları analiz etme ve yorumlama dahil araştırma yöntemlerini kullanma becerisi."}, {"id": "po_6", "code": "6", "desc_en": "Awareness of professional and ethical responsibility in engineering practice.", "desc_tr": "Mühendislik uygulamalarında mesleki ve etik sorumluluk bilinci."}, {"id": "po_7", "code": "7", "desc_en": "Awareness of the impact of engineering solutions on health, safety, and the environment.", "desc_tr": "Mühendislik çözümlerinin sağlık, güvenlik ve çevre üzerindeki etkilerinin farkında olma."}, {"id": "po_9_1", "code": "9.1", "desc_en": "Ability to communicate effectively on technical topics orally.", "desc_tr": "Teknik konularda sözlü etkin iletişim kurma becerisi."}, {"id": "po_9_2", "code": "9.2", "desc_en": "Ability to communicate effectively on technical topics in writing.",